import { callBackend } from './core';
import { BrandSettings, ImageIntent } from '../../types';
import { buildCommercialImagePrompt } from '../promptTemplates';

const ensureEnglishPrompt = async (prompt: string): Promise<string> => {
    if (/^[\x00-\x7F]*$/.test(prompt)) return prompt;
    try {
        const response = await callBackend('generateContent', {
            model: 'gemini-2.5-flash',
            contents: `Translate to descriptive English image prompt: "${prompt}". Output ONLY string.`
        });
        return response.text.trim();
    } catch (e) { return prompt; }
};

export const generateImage = async (
    prompt: string, 
    userRole: string = 'user', 
    settings?: BrandSettings, 
    intent: ImageIntent = 'lifestyle',
    textOverlay?: string
): Promise<string> => {
    const noLimitTrigger = /no limit/i.test(prompt);
    let basePrompt = prompt.replace(/no limit/ig, '').trim();

    // 1. Construct the Commercial Design Prompt
    let finalPrompt = "";
    if (settings) {
        const englishSubject = await ensureEnglishPrompt(basePrompt);
        // Pass textOverlay to builder
        finalPrompt = buildCommercialImagePrompt(englishSubject, settings, intent, userRole, textOverlay);
    } else {
        finalPrompt = await ensureEnglishPrompt(basePrompt);
        finalPrompt += ", photorealistic, cinematic lighting, photography style";
    }

    console.log("🎨 [Commercial Design Prompt]", finalPrompt);

    // 2. Select Engine
    // 'pro', 'business', 'admin' -> Priority: Backend Waterfall (Ideogram -> Imagen -> Grok)
    // 'user', 'starter' -> Frontend Economy Mode (Pollinations)

    const isProTier = ['pro', 'business', 'admin'].includes(userRole);

    if (!isProTier) {
         console.log("🎨 [ImageGen] Economy Mode: Pollinations");
         return `https://image.pollinations.ai/prompt/${encodeURIComponent(finalPrompt)}?n=${Math.floor(Math.random()*100000)}&model=flux&enhance=true`;
    }

    try {
        console.log(`🎨 [ImageGen] Pro Mode: calling Backend Waterfall`);
        const safetySettings = noLimitTrigger ? [{ category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_NONE' }] : undefined;

        // We call 'generateImages'. The backend now handles the waterfall (Ideogram -> Imagen -> Grok).
        // We don't specify model here to let backend decide based on keys.
        const response = await callBackend('generateImages', { 
            prompt: finalPrompt, 
            safetySettings 
        });

        if (response.base64) {
            console.log(`✅ Image generated via provider: ${response.provider || 'unknown'}`);
            return `data:image/png;base64,${response.base64}`;
        }
        throw new Error("No image data");
    } catch (e: any) {
        console.error("❌ [ImageGen] Backend Failed. Fallback to Pollinations.", e.message);
        return `https://image.pollinations.ai/prompt/${encodeURIComponent(finalPrompt)}?n=${Math.floor(Math.random()*100000)}&model=flux&enhance=true`;
    }
};

export const generateVideo = async (prompt: string): Promise<string> => {
    try {
        const response = await callBackend('generateVideos', {
            model: 'veo-3.1-fast-generate-preview',
            prompt: prompt,
            config: { numberOfVideos: 1, resolution: '720p', aspectRatio: '16:9' }
        });
        if (response.videoBase64) return `data:video/mp4;base64,${response.videoBase64}`;
        throw new Error("No video data returned");
    } catch (e: any) {
        console.warn("Veo failed, fallback to Image:", e);
        throw new Error(`影片生成失敗: ${e.message}`);
    }
};

export const analyzeVisualStyle = async (imageB64s: string[]): Promise<string> => {
    const parts = [
        { text: "Role: Art Director. Analyze these brand images and extract a consistent 'Visual Style Prompt' (Lighting, Color, Composition, Mood). Output concise English paragraph." },
        ...imageB64s.map(b64 => ({ inlineData: { mimeType: "image/png", data: b64.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, '') } }))
    ] as any;

    const response = await callBackend('generateContent', {
        model: "gemini-2.5-flash",
        contents: { parts }
    });
    return response.text || "Minimalist, clean, high-key lighting.";
};

export const applyWatermark = async (mainImageUrl: string, logoUrl: string): Promise<string> => {
    return new Promise((resolve, reject) => {
        if (typeof document === 'undefined') { reject(new Error("Canvas not supported")); return; }
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) { reject(new Error("Canvas context not supported")); return; }
        const mainImg = new Image(); mainImg.crossOrigin = "anonymous"; mainImg.src = mainImageUrl;
        mainImg.onload = () => {
            canvas.width = mainImg.width; canvas.height = mainImg.height; ctx.drawImage(mainImg, 0, 0);
            const logoImg = new Image(); logoImg.crossOrigin = "anonymous"; logoImg.src = logoUrl;
            logoImg.onload = () => {
                const logoW = canvas.width * 0.15; const logoH = (logoImg.height/logoImg.width)*logoW;
                const p = canvas.width * 0.05; ctx.globalAlpha = 0.9; ctx.drawImage(logoImg, canvas.width-logoW-p, canvas.height-logoH-p, logoW, logoH);
                resolve(canvas.toDataURL('image/png'));
            };
            logoImg.onerror = () => resolve(mainImageUrl);
        };
        mainImg.onerror = (e) => reject(new Error("Main image load failed"));
    });
};

import React, { useState, useEffect } from 'react';
import { BrandSettings, Post, TrendingTopic, UserProfile, ImageIntent } from '../types';
import { getTrendingTopics, generatePostDraft, generateImage, applyWatermark, generateViralContent, generateImagePromptString } from '../services/geminiService';
import { publishPostToFacebook } from '../services/facebookService';
import { checkAndUseQuota } from '../services/authService';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onPostCreated: (post: Post) => void;
  onQuotaUpdate: () => void;
  editPost?: Post | null;
  onCancel?: () => void;
  scheduledPostsCount?: number;
}

const LoadingOverlay: React.FC<{ message: string, subMessage?: string }> = ({ message, subMessage }) => (
    <div className="fixed inset-0 bg-black/80 z-50 flex flex-col items-center justify-center p-8 backdrop-blur-xl animate-fade-in text-center">
        <div className="loader mb-6 scale-150 border-t-primary"></div>
        <h2 className="text-2xl font-black text-white mb-2 tracking-tight">{message}</h2>
        {subMessage && <p className="text-gray-400 font-mono text-xs uppercase tracking-widest">{subMessage}</p>}
    </div>
);

export const PostCreator: React.FC<Props> = ({ settings, user, onPostCreated, onQuotaUpdate, editPost, onCancel, scheduledPostsCount = 0 }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [topic, setTopic] = useState('');
  const [mode, setMode] = useState<'brand' | 'viral'>('brand');

  const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
  const [isLoadingTrends, setIsLoadingTrends] = useState(false);

  const [draft, setDraft] = useState({ caption: '', firstComment: '', imagePrompt: '' });
  const [imageIntent, setImageIntent] = useState<ImageIntent>('lifestyle'); 

  // Text Overlay State
  const [wantsImageText, setWantsImageText] = useState(false);
  const [customImageText, setCustomImageText] = useState('');

  const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);
  const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
  const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);
  const [generatingPhase, setGeneratingPhase] = useState<string>(''); // For granular loading status

  const [scheduleDate, setScheduleDate] = useState('');
  const [syncInstagram, setSyncInstagram] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<{success: boolean, msg: string} | null>(null);

  const role = user?.role || 'user';
  const limit = role === 'pro' ? 5 : (role === 'business' ? 10 : (role === 'admin' ? 100 : 3));
  const isLimitReached = !editPost && scheduledPostsCount >= limit;

  useEffect(() => {
    if (editPost) {
        setStep(2);
        setTopic(editPost.topic);
        setDraft({ caption: editPost.caption, firstComment: editPost.firstComment || '', imagePrompt: editPost.mediaPrompt });
        setMediaUrl(editPost.mediaUrl);
        setScheduleDate(editPost.scheduledDate || '');
        setSyncInstagram(!!editPost.syncInstagram);
    }
  }, [editPost]);

  const loadTrends = async () => {
      if (!user) return alert("請先登入");

      const COST = 3; 
      const allowed = await checkAndUseQuota(user.user_id, COST, 'TREND_SEARCH'); 
      if (!allowed) return; 

      onQuotaUpdate();
      setIsLoadingTrends(true);
      try {
          const query = topic.trim() || settings.industry || '台灣熱門話題';
          const trends = await getTrendingTopics(query);
          setTrendingTopics(trends);
          if(topic.trim()) alert(`已為您搜尋關於「${query}」的熱門話題！(扣除 ${COST} 點)`);
      } catch (e) { console.error(e); }
      finally { setIsLoadingTrends(false); }
  };

  const handleNext = async () => {
    if (!topic || !user) return;

    // [BILLING] FB Draft: 5 Points
    const allowed = await checkAndUseQuota(user.user_id, 5, 'GENERATE_POST_DRAFT');
    if (!allowed) return; 

    onQuotaUpdate();
    setStep(2);
    setIsGeneratingDraft(true);
    setMediaUrl(undefined); 

    try {
        if (mode === 'brand') {
            const res = await generatePostDraft(topic, settings, { 
                length: '150-300字', 
                ctaList: [], 
                tempHashtags: '', 
                includeEngagement: false 
            }, undefined, user.role);

            setDraft({ 
                caption: res.caption || '', 
                firstComment: res.ctaText || '', 
                imagePrompt: '' 
            });
        } else {
            const res = await generateViralContent(topic, {
                audience: '社群大眾',
                viralType: 'auto',
                platform: 'facebook',
                versionCount: 1
            }, settings);
            setDraft({
                caption: res.versions?.[0] || '生成內容為空，請重試',
                firstComment: '',
                imagePrompt: ''
            });
        }
    } catch (e: any) { 
        alert(`失敗: ${e.message}`); 
        setStep(1); 
    } finally { 
        setIsGeneratingDraft(false); 
    }
  };

  const handleGenMedia = async () => {
    if (!user || isGeneratingMedia) return;

    // Text safety check
    if (wantsImageText && !customImageText) {
        return alert("請輸入您想顯示在圖片上的文字，或關閉「嘗試嵌入文字」功能。");
    }

    // [BILLING] FB Image: Regen 5 Points, First Time 8 Points
    const cost = mediaUrl ? 5 : 8; 
    const allowed = await checkAndUseQuota(user.user_id, cost, 'GENERATE_IMAGE_AI');
    if (!allowed) return;

    onQuotaUpdate();
    setIsGeneratingMedia(true);
    setGeneratingPhase('正在構思畫面...');

    try {
        let finalPrompt = draft.imagePrompt;

        if (!finalPrompt.trim()) {
             const aiPrompt = await generateImagePromptString(draft.caption, imageIntent, settings);
             finalPrompt = aiPrompt;
             setDraft(prev => ({ ...prev, imagePrompt: aiPrompt }));
        }

        setGeneratingPhase('AI 設計師繪圖中 (標準畫質)...');

        // Use new generateImage with Settings, Intent, AND optional textOverlay
        let url = await generateImage(
            finalPrompt, 
            user.role, 
            settings, 
            imageIntent,
            wantsImageText ? customImageText : undefined
        );

        if (settings.logoUrl) {
            setGeneratingPhase('正在壓上品牌浮水印...');
            url = await applyWatermark(url, settings.logoUrl);
        }
        setMediaUrl(url);
    } catch (e: any) { 
        alert(`製圖失敗: ${e.message}`); 
    } finally { 
        setIsGeneratingMedia(false); 
        setGeneratingPhase('');
    }
  };

  const handleIntentChange = (newIntent: ImageIntent) => {
      setImageIntent(newIntent);
  };

  const handleFinalize = async (schedule: boolean) => {
    if (!user || isPublishing) return;
    let scheduledUnixTime: number | undefined = undefined;

    if (schedule) {
        if (!scheduleDate) return alert("請選擇預計發佈時間");
        const targetTime = new Date(scheduleDate).getTime();
        const now = Date.now();
        const diffMinutes = (targetTime - now) / 1000 / 60;
        if (diffMinutes < 10) return alert("FB 規定：排程時間必須在「未來 10 分鐘」之後。");
        if (diffMinutes > 30 * 24 * 60) return alert("FB 規定：排程時間不能超過 30 天。");
        scheduledUnixTime = Math.floor(targetTime / 1000);
    }

    setIsPublishing(true);
    try {
        const newPost: Post = {
          id: editPost ? editPost.id : Date.now().toString(),
          userId: user.user_id,
