const defaultSettings: BrandSettings = {
  industry: '',
  brandName: '', 
  brandType: 'enterprise',
  services: '',
  website: '',
  productInfo: '',
  brandTone: 'Professional',
  persona: '',
  brandColors: ['#000000', '#ffffff', '#cccccc'],
  targetAudience: '',
  visualStyle: 'minimalist',
  facebookPageId: '',
  facebookToken: '',
  threadsAccounts: [], 
  referenceFiles: [],
  fixedHashtags: '',
  autoReply: { enabled: false, defaultResponse: '', rules: [] },
  autoPilot: {
    enabled: false,
    frequency: 'daily',
    postTime: '09:00',
    source: 'trending',
    keywords: [],
    mediaTypePreference: 'image'
  }
};

const App: React.FC = () => {
  const [user, setUser] = useState<any>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [loadingAuth, setLoadingAuth] = useState(true);
  const [view, setView] = useState<AppView>(AppView.LOGIN);
  const [settings, setSettings] = useState<BrandSettings>(defaultSettings);
  const [posts, setPosts] = useState<Post[]>([]);
  const [editingPost, setEditingPost] = useState<Post | null>(null);

  // Navigation State for Stock Market
  const [prefilledTopic, setPrefilledTopic] = useState('');

  const [showReportModal, setShowReportModal] = useState(false);
  const [showKeyModal, setShowKeyModal] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isProcessingThreads, setIsProcessingThreads] = useState(false);

  // ... (Existing OAuth and Auth Logic) ...
  useEffect(() => {
      const params = new URLSearchParams(window.location.search);
      const code = params.get('code');
      if (code && window.opener && window.opener !== window) {
          console.log("🔐 [threads] Popup detected, sending code to parent...");
          window.opener.postMessage({ type: 'THREADS_OAUTH_CODE', code }, window.location.origin);
          window.close();
      }
  }, []);

  useEffect(() => {
    const unsubscribe = subscribeAuth(async (currentUser) => {
      setUser(currentUser);
      if (currentUser) {
        const profile = await getUserProfile(currentUser.uid);
        setUserProfile(profile);
        // Default to Market view on login
        setView(AppView.MARKET);
        loadLocalSettings();
        const cloudPosts = await fetchUserPostsFromCloud(currentUser.uid);
        setPosts(cloudPosts);
      } else {
        setUserProfile(null);
        setView(AppView.LOGIN);
      }
      setLoadingAuth(false);
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
      const handleThreadsCallback = async () => {
          if (loadingAuth || !user) return; 
          const params = new URLSearchParams(window.location.search);
          const code = params.get('code');
          if (code && !window.opener) {
              if (isProcessingThreads) return;
              setIsProcessingThreads(true);
              try {
                  if (!localStorage.getItem('autosocial_pending_oauth')) return; 
                  const result = await exchangeThreadsAuth(code, window.location.origin);
                  const newAccount: ThreadsAccount = {
                      id: Date.now().toString(),
                      userId: result.userId,
                      token: result.token,
                      username: result.username || `User_${result.userId.slice(-4)}`,
                      isActive: true,
                      accountType: 'personal',
                      styleGuide: ''
                  };
                  const updatedSettings = {
                      ...settings,
                      threadsAccounts: [...(settings.threadsAccounts || []), newAccount]
                  };
                  setSettings(updatedSettings);
                  localStorage.setItem('autosocial_settings', JSON.stringify(updatedSettings));
                  localStorage.removeItem('autosocial_pending_oauth'); 
                  alert(`Threads 帳號 ${newAccount.username} 連接成功！`);
                  window.history.replaceState({}, document.title, window.location.pathname);
                  setView(AppView.THREADS_NURTURE);
              } catch (e: any) {
                  alert(`Threads 串接失敗: ${e.message}`);
              } finally {
                  setIsProcessingThreads(false);
              }
          }
      };
      handleThreadsCallback();
  }, [loadingAuth, user, settings]); 

  const loadLocalSettings = () => {
    const savedSettings = localStorage.getItem('autosocial_settings');
    if (savedSettings) {
        try {
            const parsed = JSON.parse(savedSettings);
            setSettings({ ...defaultSettings, ...parsed });
        } catch (e) {}
    }
  };

  const handleLogout = async () => {
    await logout();
    setView(AppView.LOGIN);
  };

  const refreshProfile = async () => {
    if (user) {
      const profile = await getUserProfile(user.uid);
      setUserProfile(profile);
    }
  };

  const handleSaveSettings = (newSettings: BrandSettings) => {
    setSettings(newSettings);
    localStorage.setItem('autosocial_settings', JSON.stringify(newSettings));
  };

  const handlePostCreated = async (newPost: Post) => {
    if (!user || !userProfile) return;
    if (newPost.status === 'scheduled') {
        const scheduledCount = posts.filter(p => p.status === 'scheduled' && p.id !== newPost.id).length;
        const role = userProfile.role;
        let limit = 3; 
        if (role === 'pro') limit = 5;
        else if (role === 'business') limit = 10;
        else if (role === 'admin') limit = 100;
        if (scheduledCount >= limit) {
            alert(`⚠️ 排程空間不足！您的方案最多儲存 ${limit} 篇排程貼文。`);
            return;
        }
    }
    try {
        setPosts(prev => {
            const exists = prev.find(p => p.id === newPost.id);
            if (exists) return prev.map(p => p.id === newPost.id ? newPost : p);
            return [newPost, ...prev];
        });
        await syncPostToCloud(user.uid, newPost);
        const updatedPosts = await fetchUserPostsFromCloud(user.uid);
        setPosts(updatedPosts);
        setEditingPost(null);
        setView(AppView.SCHEDULE);
    } catch (e: any) {
        alert(`同步失敗: ${e.message}`);
    }
  };

  const handleDeletePost = async (postId: string) => {
      if (!user) return;
      try {
          await deletePostFromCloud(user.uid, postId);
          setPosts(prev => prev.filter(p => p.id !== postId));
      } catch (e) { alert("刪除失敗"); }
  };

  const handleEditPost = (post: Post) => {
      setEditingPost(post);
      setView(AppView.CREATE);
  };

  const handleStockNavigate = (topic: string, platform: 'fb' | 'threads') => {
      setPrefilledTopic(topic);
      if (platform === 'fb') {
          // Navigate to FB Creator, passing topic via state
          // Editing post must be null to trigger fresh state in PostCreator
          setEditingPost(null); 
          setView(AppView.CREATE);
      } else {
          // Navigate to Threads Nurture Panel
          setView(AppView.THREADS_NURTURE);
      }
  };

  const role = userProfile?.role || 'user';
  const isAdmin = role === 'admin';
  const isStarterPlus = ['starter', 'pro', 'business', 'admin'].includes(role);
  const isProPlus = ['pro', 'business', 'admin'].includes(role);
  const isBusinessPlus = ['business', 'admin'].includes(role);

  const hasAnalyticsAccess = isStarterPlus || userProfile?.unlockedFeatures?.includes('ANALYTICS');
  const hasAutomationAccess = isProPlus || userProfile?.unlockedFeatures?.includes('AUTOMATION');
  const hasSeoAccess = isProPlus || userProfile?.unlockedFeatures?.includes('SEO');
  const hasThreadsAccess = isProPlus || userProfile?.unlockedFeatures?.includes('THREADS');

  // Check params for OAuth Authorizing view
  const searchParams = new URLSearchParams(window.location.search);

  if (loadingAuth) return <div className="h-screen flex items-center justify-center bg-bg text-primary text-xl animate-pulse font-mono tracking-widest">INITIALIZING SYSTEM...</div>;
  if (searchParams.get('code') && window.opener) return <div className="h-screen flex items-center justify-center bg-black text-white text-sm font-mono">🔐 Authorizing Threads... (Closing soon)</div>;
  if (isProcessingThreads) return <div className="h-screen flex items-center justify-center bg-bg text-pink-500 text-xl font-bold animate-pulse">正在與 Threads 進行安全連線...</div>;
  if (view === AppView.LOGIN) return <Login onLoginSuccess={() => {}} />;

  const NavItem = ({ viewId, label, active, onClick, disabled = false, badge = "", icon }: any) => (
    <button 
      onClick={() => {
          if (!disabled) {
              onClick(viewId);
              setIsSidebarOpen(false); 
          }
      }} 
      className={`relative w-full text-left px-6 py-3.5 transition-all duration-300 flex items-center justify-between group 
        ${active ? 'bg-primary/10 text-primary' : 'text-gray-400 hover:text-white hover:bg-white/5'} 
        ${disabled ? 'opacity-40 cursor-not-allowed grayscale' : ''}
        border-l-2 ${active ? 'border-primary' : 'border-transparent hover:border-white/30'}
      `}
    >
      {active && <div className="absolute inset-0 bg-primary/5 shadow-[0_0_20px_rgba(0,242,234,0.1)]"></div>}
      <div className="flex items-center gap-3 relative z-10">
          <span className={`transition-transform duration-300 ${active ? 'scale-110' : 'group-hover:scale-110'}`}>{icon}</span>
          <span className="text-[14px] font-medium tracking-wide">{label}</span>
      </div>
      {badge && <span className="text-[9px] bg-black/50 border border-gray-700 px-1.5 py-0.5 rounded uppercase tracking-tighter text-gray-400 font-bold">{badge}</span>}
    </button>
  );

  return (
    <div className="min-h-screen text-gray-200 flex flex-col md:flex-row relative font-sans overflow-hidden">

      {/* Mobile Header */}
      <div className="md:hidden flex justify-between items-center p-4 glass-panel border-b border-white/10 relative z-50">
          <h1 className="text-lg font-black tracking-tighter text-white flex items-center gap-2">
            AUTO<span className="text-neon-cyan">SOCIAL</span>
          </h1>
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="text-white p-2">
             {isSidebarOpen ? Icons.Close : Icons.Menu}
          </button>
      </div>

      {/* Glass Sidebar */}
      <aside className={`
          fixed md:relative inset-y-0 left-0 w-72 glass-panel z-40 transform transition-transform duration-300 ease-out flex flex-col
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <div className="p-8 pb-4">
          <h1 className="text-2xl font-black text-white tracking-tighter cursor-pointer flex items-center gap-2 select-none" onClick={() => setView(AppView.MARKET)}>
            AUTO<span className="text-neon-cyan drop-shadow-[0_0_8px_rgba(0,242,234,0.6)]">SOCIAL</span>
          </h1>
          {isMock && <div className="mt-2 text-[10px] bg-yellow-500/20 text-yellow-400 px-2 py-1 rounded border border-yellow-500/50 text-center font-bold tracking-wider">⚠️ Preview Mode (Mock Data)</div>}
          <div className="mt-6 p-4 glass-card rounded-xl border border-white/10 bg-black/20">
            {userProfile ? (
                <>
                    <div className="flex justify-between items-start mb-2">
                        <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-primary to-accent flex items-center justify-center text-black font-bold text-xs">
                            {userProfile.email[0].toUpperCase()}
                        </div>
                        <div className={`text-[10px] px-2 py-0.5 rounded font-black uppercase tracking-wider ${userProfile.role === 'admin' ? 'bg-red-500/20 text-red-400 border border-red-500/50' : userProfile.role === 'business' ? 'bg-yellow-500/20 text-yellow-400 border border-yellow-500/50' : 'bg-primary/20 text-primary border border-primary/50'}`}>
                            {userProfile.role}
                        </div>
                    </div>
                    <p className="truncate text-xs text-gray-400 mb-3 font-mono">{userProfile.email}</p>
                    <div className="w-full bg-gray-800 h-1.5 rounded-full overflow-hidden mb-1">
                        <div className="h-full bg-primary shadow-[0_0_10px_#00f2ea]" style={{ width: `${Math.min(100, (userProfile.quota_used / userProfile.quota_total) * 100)}%` }}></div>
                    </div>
                    <div className="flex justify-between text-[10px] text-gray-500 font-bold mb-2"><span>點數</span><span>{userProfile.quota_used} / {userProfile.quota_total}</span></div>
                </>
            ) : <p className="text-xs text-gray-500">GUEST MODE</p>}
          </div>
        </div>

        <nav className="flex-1 py-4 space-y-1 overflow-y-auto custom-scrollbar">
          <NavItem viewId={AppView.MARKET} label="社群交易所" icon={Icons.Market} active={view === AppView.MARKET} onClick={setView} badge="HOT" />
          <NavItem viewId={AppView.CREATE} label="內容創作" icon={Icons.Create} active={view === AppView.CREATE} onClick={setView} />
          <NavItem viewId={AppView.SCHEDULE} label="排程與歷史" icon={Icons.Schedule} active={view === AppView.SCHEDULE} onClick={setView} />
          <NavItem viewId={AppView.SETTINGS} label="品牌設定" icon={Icons.Settings} active={view === AppView.SETTINGS} onClick={setView} />

          <div className="mt-6 mb-2 px-6">
              <p className="text-[10px] text-gray-500 font-black tracking-[0.2em] uppercase">智慧功能</p>
          </div>
          <NavItem viewId={AppView.ANALYTICS} label="數據分析" icon={Icons.Analytics} active={view === AppView.ANALYTICS} onClick={() => hasAnalyticsAccess ? setView(AppView.ANALYTICS) : alert("需升級至 Starter 方案")} disabled={!hasAnalyticsAccess} badge={!hasAnalyticsAccess ? "LOCKED" : ""} />
          <NavItem viewId={AppView.AUTOMATION} label="全自動化" icon={Icons.Automation} active={view === AppView.AUTOMATION} onClick={() => hasAutomationAccess ? setView(AppView.AUTOMATION) : alert("需升級至 Pro 方案")} disabled={!hasAutomationAccess} badge={!hasAutomationAccess ? "LOCKED" : ""} />
          <NavItem viewId={AppView.SEO_ARTICLES} label="SEO 文章" icon={Icons.Seo} active={view === AppView.SEO_ARTICLES} onClick={() => hasSeoAccess ? setView(AppView.SEO_ARTICLES) : alert("需升級至 Pro 方案")} disabled={!hasSeoAccess} badge={!hasSeoAccess ? "LOCKED" : ""} />
          <NavItem viewId={AppView.THREADS_NURTURE} label="Threads 進階" icon={Icons.Threads} active={view === AppView.THREADS_NURTURE} onClick={() => hasThreadsAccess ? setView(AppView.THREADS_NURTURE) : alert("需升級至 Pro 方案")} disabled={!hasThreadsAccess} badge={!hasThreadsAccess ? "LOCKED" : ""} />
          <NavItem viewId={AppView.CONNECT} label="口碑媒合" icon={Icons.Connect} active={view === AppView.CONNECT} onClick={setView} />

          <div className="mt-6 mb-2 px-6">
              <p className="text-[10px] text-gray-500 font-black tracking-[0.2em] uppercase">成長工具</p>
          </div>
          <NavItem viewId={AppView.PRICING} label="費率說明" icon={Icons.Pricing} active={view === AppView.PRICING} onClick={setView} />
          <NavItem viewId={AppView.REFERRAL} label="推薦計畫" icon={Icons.Referral} active={view === AppView.REFERRAL} onClick={setView} />
        </nav>

        <div className="p-4 bg-black/20 space-y-2 border-t border-white/5">
          <button onClick={() => setShowKeyModal(true)} className="w-full text-left px-4 py-3 text-xs rounded-lg transition-all font-bold bg-yellow-500/10 text-yellow-400 hover:bg-yellow-500/20 border border-yellow-500/20 flex items-center gap-2 group"><span className="opacity-80 group-hover:scale-110 transition-transform">{Icons.Key}</span> 兌換序號</button>
          <button onClick={() => setView(AppView.CONTACT_SUPPORT)} className="w-full text-left px-4 py-3 text-xs rounded-lg transition-all font-bold bg-blue-900/20 text-blue-300 hover:bg-blue-900/40 border border-blue-800/30 flex items-center gap-2 group"><span className="opacity-80 group-hover:scale-110 transition-transform">{Icons.Support}</span> 聯繫客服</button>
          {isAdmin && <button onClick={() => setView(AppView.ADMIN)} className={`w-full text-left px-4 py-3 text-xs rounded-lg transition-all font-bold flex items-center gap-2 group ${view === AppView.ADMIN ? 'bg-red-600 text-white shadow-lg' : 'text-red-400 hover:bg-red-900/20 border border-red-900/30'}`}><span className="opacity-80 group-hover:scale-110 transition-transform">{Icons.Admin}</span> 管理員後台</button>}
          <button onClick={handleLogout} className="w-full text-left px-4 py-3 text-xs text-gray-500 hover:text-white transition-colors flex items-center gap-2 group hover:bg-white/5 rounded-lg"><span className="opacity-80 group-hover:scale-110 transition-transform">{Icons.Logout}</span> 登出系統</button>
        </div>
      </aside>

      <main className="flex-1 p-4 md:p-8 lg:p-12 overflow-y-auto h-screen custom-scrollbar relative">
        <div className="max-w-7xl mx-auto h-full">
            {view === AppView.MARKET && (
                <SocialStockMarket 
                    user={userProfile} 
                    onNavigateToCreate={handleStockNavigate} 
                    onQuotaUpdate={refreshProfile} 
                />
            )}
            {view === AppView.CREATE && (
              <PostCreator 
                settings={settings} 
                user={userProfile} 
                onPostCreated={handlePostCreated} 
                onQuotaUpdate={refreshProfile} 
                editPost={editingPost} 
                onCancel={() => setEditingPost(null)}
                scheduledPostsCount={posts.filter(p => p.status === 'scheduled').length}
                initialTopic={prefilledTopic}
              />
            )}
            {view === AppView.SCHEDULE && (
              <ScheduleList 
                  posts={posts} 
                  onUpdatePosts={async (updated) => {
                      const originalIds = posts.map(p => p.id);
                      const updatedIds = updated.map(p => p.id);
                      const deletedId = originalIds.find(id => !updatedIds.includes(id));
                      if (deletedId) await handleDeletePost(deletedId);
                      else {
                          const changed = updated.find((p, i) => JSON.stringify(p) !== JSON.stringify(posts.find(op => op.id === p.id)));
                          if (changed && user) await syncPostToCloud(user.uid, changed);
                          setPosts(updated);
                      }
                  }} 
                  onEditPost={handleEditPost}
                  settings={settings}
              />
            )}
            {view === AppView.SETTINGS && <SettingsForm onSave={handleSaveSettings} initialSettings={settings} />}
            {view === AppView.ANALYTICS && <AnalyticsDashboard settings={settings} />}
            {view === AppView.AUTOMATION && <AutomationPanel settings={settings} onSave={handleSaveSettings} />}
            {view === AppView.SEO_ARTICLES && <SeoArticleGenerator user={userProfile} onQuotaUpdate={refreshProfile} />}
            {view === AppView.THREADS_NURTURE && <ThreadsNurturePanel settings={settings} user={userProfile} onSaveSettings={handleSaveSettings} onQuotaUpdate={refreshProfile} initialTopic={prefilledTopic} />}
            {view === AppView.CONNECT && <ConnectPanel settings={settings} user={userProfile} onQuotaUpdate={refreshProfile} />}
            {view === AppView.PRICING && <PricingPanel user={userProfile} onContactClick={() => setView(AppView.CONTACT_SUPPORT)} />}
            {view === AppView.REFERRAL && <ReferralPanel user={userProfile} onQuotaUpdate={refreshProfile} />}
            {view === AppView.CONTACT_SUPPORT && <ContactSupportPanel />}
            {view === AppView.ADMIN && isAdmin && <AdminPanel currentUser={userProfile!} />}
        </div>
      </main>

      {userProfile && <AiAssistantBubble currentView={view} settings={settings} />}
      <QueueOverlay />
      <button onClick={() => setShowReportModal(true)} className="fixed bottom-6 right-6 bg-red-600 hover:bg-red-500 text-white w-12 h-12 rounded-full z-50 shadow-[0_0_20px_rgba(220,38,38,0.5)] transition-transform active:scale-90 flex items-center justify-center font-bold text-xl backdrop-blur-md border border-white/20" title="回報問題">!</button>
      {showReportModal && <ErrorReportModal user={userProfile} currentView={view} onClose={() => setShowReportModal(false)} />}
      {showKeyModal && userProfile && <KeyRedemptionModal user={userProfile} onClose={() => setShowKeyModal(false)} onSuccess={refreshProfile} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { BrandSettings, Post, TrendingTopic, UserProfile, ImageIntent } from '../types';
import { getTrendingTopics, generatePostDraft, generateImage, applyWatermark, generateViralContent, generateImagePromptString, compositeImageWithText } from '../services/geminiService';
import { publishPostToFacebook } from '../services/facebookService';
import { checkAndUseQuota } from '../services/authService';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onPostCreated: (post: Post) => void;
  onQuotaUpdate: () => void;
  editPost?: Post | null;
  onCancel?: () => void;
  scheduledPostsCount?: number;
  initialTopic?: string; // New Prop
}

const LoadingOverlay: React.FC<{ message: string, subMessage?: string }> = ({ message, subMessage }) => (
    <div className="fixed inset-0 bg-black/80 z-50 flex flex-col items-center justify-center p-8 backdrop-blur-xl animate-fade-in text-center">
        <div className="loader mb-6 scale-150 border-t-primary"></div>
        <h2 className="text-2xl font-black text-white mb-2 tracking-tight">{message}</h2>
        {subMessage && <p className="text-gray-400 font-mono text-xs uppercase tracking-widest">{subMessage}</p>}
    </div>
);

export const PostCreator: React.FC<Props> = ({ settings, user, onPostCreated, onQuotaUpdate, editPost, onCancel, scheduledPostsCount = 0, initialTopic }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [topic, setTopic] = useState('');
  const [mode, setMode] = useState<'brand' | 'viral'>('brand');

  const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
  const [isLoadingTrends, setIsLoadingTrends] = useState(false);

  const [draft, setDraft] = useState({ caption: '', firstComment: '', imagePrompt: '' });
  const [imageIntent, setImageIntent] = useState<ImageIntent>('lifestyle'); 

  // Image Rendering Modes
  const [renderMode, setRenderMode] = useState<'plain' | 'ai_text' | 'smart_layout'>('plain');
  const [customImageText, setCustomImageText] = useState(''); // Used for AI Text Mode

  // Smart Layout State
  const [layoutTitle, setLayoutTitle] = useState('');
  const [layoutSubtitle, setLayoutSubtitle] = useState('');

  const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);
  const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
  const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);
  const [generatingPhase, setGeneratingPhase] = useState<string>(''); 

  const [scheduleDate, setScheduleDate] = useState('');
  const [syncInstagram, setSyncInstagram] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<{success: boolean, msg: string} | null>(null);

  const role = user?.role || 'user';
  const limit = role === 'pro' ? 5 : (role === 'business' ? 10 : (role === 'admin' ? 100 : 3));
  const isLimitReached = !editPost && scheduledPostsCount >= limit;

  // Handle Edit Post Logic
  useEffect(() => {
    if (editPost) {
        setStep(2);
        setTopic(editPost.topic);
        setDraft({ caption: editPost.caption, firstComment: editPost.firstComment || '', imagePrompt: editPost.mediaPrompt });
        setMediaUrl(editPost.mediaUrl);
        setScheduleDate(editPost.scheduledDate || '');
        setSyncInstagram(!!editPost.syncInstagram);
    }
  }, [editPost]);

  // Handle Initial Topic from Stock Market
  useEffect(() => {
      if (initialTopic) {
          setTopic(initialTopic);
          setStep(1); // Stay on step 1 to confirm generation
      }
  }, [initialTopic]);

  // Pre-fill smart layout text based on topic when draft is generated
  useEffect(() => {
      if (draft.caption && !layoutTitle) {
          // Heuristic: Use topic as title, extract first price or short phrase as subtitle
          setLayoutTitle(topic);
          const priceMatch = draft.caption.match(/\$\d+(?:,\d+)?/);
          if (priceMatch) setLayoutSubtitle(`${priceMatch[0]} 起`);
      }
  }, [draft.caption]);

  const loadTrends = async () => {
      if (!user) return alert("請先登入");

      const COST = 3; 
      const allowed = await checkAndUseQuota(user.user_id, COST, 'TREND_SEARCH'); 
      if (!allowed) return; 

      onQuotaUpdate();
      setIsLoadingTrends(true);
      try {
          const query = topic.trim() || settings.industry || '台灣熱門話題';
          const trends = await getTrendingTopics(query);
          setTrendingTopics(trends);
          if(topic.trim()) alert(`已為您搜尋關於「${query}」的熱門話題！(扣除 ${COST} 點)`);
      } catch (e) { console.error(e); }
      finally { setIsLoadingTrends(false); }
  };

  const handleNext = async () => {
    if (!topic || !user) return;

    // [BILLING] FB Draft: 5 Points
    const allowed = await checkAndUseQuota(user.user_id, 5, 'GENERATE_POST_DRAFT');
    if (!allowed) return; 

    onQuotaUpdate();
    setStep(2);
    setIsGeneratingDraft(true);
    setMediaUrl(undefined); 

    try {
        if (mode === 'brand') {
            const res = await generatePostDraft(topic, settings, { 
                length: '150-300字', 
                ctaList: [], 
                tempHashtags: '', 
                includeEngagement: false 
            }, undefined, user.role);

            setDraft({ 
                caption: res.caption || '', 
                firstComment: res.ctaText || '', 
                imagePrompt: '' 
            });
        } else {
            const res = await generateViralContent(topic, {
                audience: '社群大眾',
                viralType: 'auto',
                platform: 'facebook',
                versionCount: 1
            }, settings);
            setDraft({
                caption: res.versions?.[0] || '生成內容為空，請重試',
                firstComment: '',
                imagePrompt: ''
            });
        }
    } catch (e: any) { 
        alert(`失敗: ${e.message}`); 
        setStep(1); 
    } finally { 
        setIsGeneratingDraft(false); 
    }
  };

  const handleGenMedia = async () => {
    if (!user || isGeneratingMedia) return;

    // Validation
    if (renderMode === 'ai_text' && !customImageText) {
        return alert("請輸入您想顯示在圖片上的文字，或切換模式。");
    }
    if (renderMode === 'smart_layout' && !layoutTitle) {
        return alert("智慧排版模式需要至少輸入「主標題」。");
    }

    // [BILLING] FB Image: Regen 5 Points, First Time 8 Points
    const cost = mediaUrl ? 5 : 8; 
    const allowed = await checkAndUseQuota(user.user_id, cost, 'GENERATE_IMAGE_AI');
    if (!allowed) return;

    onQuotaUpdate();
    setIsGeneratingMedia(true);
    setGeneratingPhase('正在構思畫面...');

    try {
        let finalPrompt = draft.imagePrompt;

        if (!finalPrompt.trim()) {
             const aiPrompt = await generateImagePromptString(draft.caption, imageIntent, settings);
             finalPrompt = aiPrompt;
             setDraft(prev => ({ ...prev, imagePrompt: aiPrompt }));
        }

        setGeneratingPhase('AI 設計師繪圖中 (標準畫質)...');

        // Step 1: Generate Base Image
        // If smart_layout, we pass true to ask AI for negative space.
        // If ai_text, we pass the text string.
        let url = await generateImage(
            finalPrompt, 
            user.role, 
            settings, 
            imageIntent,
            renderMode === 'ai_text' ? customImageText : undefined,
            renderMode === 'smart_layout' // useSmartLayout flag
        );

        // Step 2: Apply Canvas Overlay (If Smart Layout)
        if (renderMode === 'smart_layout') {
            setGeneratingPhase('正在進行智慧排版合成...');
            url = await compositeImageWithText(url, layoutTitle, layoutSubtitle, '#FFD700');
        }

        // Step 3: Apply Logo
        if (settings.logoUrl) {
            setGeneratingPhase('正在壓上品牌浮水印...');
            url = await applyWatermark(url, settings.logoUrl);
        }
        setMediaUrl(url);
    } catch (e: any) { 
        alert(`製圖失敗: ${e.message}`); 
    } finally { 
        setIsGeneratingMedia(false); 
        setGeneratingPhase('');
    }
  };

  const handleIntentChange = (newIntent: ImageIntent) => {
      setImageIntent(newIntent);
  };

  const handleFinalize = async (schedule: boolean) => {
    if (!user || isPublishing) return;
    let scheduledUnixTime: number | undefined = undefined;

    if (schedule) {
        if (!scheduleDate) return alert("請選擇預計發佈時間");
        const targetTime = new Date(scheduleDate).getTime();
        const now = Date.now();
        const diffMinutes = (targetTime - now) / 1000 / 60;
        if (diffMinutes < 10) return alert("FB 規定：排程時間必須在「未來 10 分鐘」之後。");
        if (diffMinutes > 30 * 24 * 60) return alert("FB 規定：排程時間不能超過 30 天。");
        scheduledUnixTime = Math.floor(targetTime / 1000);
    }

    setIsPublishing(true);
    try {
        const newPost: Post = {
          id: editPost ? editPost.id : Date.now().toString(),
          userId: user.user_id,
          topic,
          caption: draft.caption, 
          firstComment: draft.firstComment,
          mediaPrompt: draft.imagePrompt,
          mediaType: 'image',
          mediaUrl,
          status: schedule ? 'scheduled' : 'published',
          scheduledDate: schedule ? scheduleDate : undefined, 
          syncInstagram,
          createdAt: editPost ? editPost.createdAt : Date.now()
        };

        const res = await publishPostToFacebook(
            settings.facebookPageId, 
            settings.facebookToken, 
            draft.caption, 
            mediaUrl, 
            draft.firstComment, 
            syncInstagram,
            scheduledUnixTime
        );

        if (res.success) {
            newPost.publishedUrl = res.url;
            newPost.status = schedule ? 'scheduled' : 'published';
            await onPostCreated(newPost);

            if (schedule) setPublishResult({ success: true, msg: "✅ 已成功傳送至 Facebook 排程系統！" });
            else setPublishResult({ success: true, msg: "✅ 貼文已成功發佈！" });
        } else {
            newPost.status = 'failed';
            newPost.errorLog = res.error;
            await onPostCreated(newPost);
            setPublishResult({ success: false, msg: `❌ 發佈失敗: ${res.error}` });
        }

    } catch (err: any) { 
        setPublishResult({ success: false, msg: `錯誤: ${err.message}` }); 
    } finally { 
        setIsPublishing(false); 
    }
  };

  if (isGeneratingDraft) return <LoadingOverlay message="AI 正在構思文案..." />;
  if (isGeneratingMedia) return <LoadingOverlay message={generatingPhase} subMessage="請稍候，正在為您打造專屬素材" />;
  if (isPublishing) return <LoadingOverlay message="正在傳送至 Facebook..." />;

  if (step === 1) return (
      <div className="max-w-4xl mx-auto space-y-8 md:space-y-12 animate-fade-in pt-4 md:pt-10">
          <div className="text-center space-y-3">
              <h2 className="text-3xl md:text-5xl font-black text-white tracking-tighter drop-shadow-[0_0_15px_rgba(255,255,255,0.2)]">
                  What's Next?
              </h2>
              <p className="text-gray-400 font-bold tracking-widest uppercase text-xs md:text-base">輸入核心主題，讓 AI 為您打造吸睛內容</p>
          </div>

          <div className="glass-card p-6 md:p-12 rounded-[2rem] shadow-2xl space-y-6 md:space-y-8 relative overflow-hidden">
              <div className="absolute top-0 right-0 w-64 h-64 bg-primary/20 blur-[100px] rounded-full pointer-events-none"></div>

              <div className="flex p-1.5 bg-black/40 rounded-2xl border border-white/5 relative z-10">
                  <button onClick={() => setMode('brand')} className={`flex-1 py-3 md:py-4 rounded-xl font-bold tracking-wide transition-all text-sm md:text-base ${mode === 'brand' ? 'bg-primary text-black shadow-[0_0_20px_rgba(0,242,234,0.4)]' : 'text-gray-500 hover:text-white'}`}>品牌模式</button>
                  <button onClick={() => setMode('viral')} className={`flex-1 py-3 md:py-4 rounded-xl font-bold tracking-wide transition-all text-sm md:text-base ${mode === 'viral' ? 'bg-secondary text-white shadow-[0_0_20px_rgba(255,0,85,0.4)]' : 'text-gray-500 hover:text-white'}`}>爆文模式 (小紅書)</button>
              </div>

              <div className="flex flex-col md:flex-row gap-3 relative z-10">
                  <input value={topic} onChange={e => setTopic(e.target.value)} className="flex-1 p-4 md:p-5 rounded-2xl text-lg md:text-xl font-medium placeholder-gray-600 outline-none w-full" placeholder="輸入主題 (例如：夏季保養、今日新聞...)" />
                  <button onClick={loadTrends} className="bg-gray-800 hover:bg-gray-700 px-8 py-4 md:py-0 rounded-2xl text-white font-bold transition-all flex flex-row md:flex-col items-center justify-center gap-2 md:gap-1 border border-gray-700 hover:border-white/20 whitespace-nowrap">
                    <span className="text-sm">🔥 挖掘靈感</span><span className="text-[9px] bg-primary/20 text-primary px-2 rounded-full font-black">3 點數</span>
                  </button>
              </div>

              {isLoadingTrends ? (
                  <div className="flex justify-center py-6"><div className="loader border-t-primary"></div></div>
              ) : trendingTopics.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-72 overflow-y-auto p-4 border border-white/5 rounded-2xl bg-black/20 custom-scrollbar relative z-10">
                      {trendingTopics.map((t, i) => (
                          <div key={i} onClick={() => setTopic(t.title)} className={`p-4 rounded-xl cursor-pointer transition-all group backdrop-blur-md ${topic === t.title ? 'bg-primary/20 border-primary border' : 'bg-white/5 border-transparent border hover:border-white/20 hover:bg-white/10'}`}>
                              <h4 className="font-bold text-white text-sm mb-1 line-clamp-1 group-hover:text-primary transition-colors">{t.title}</h4>
                              <p className="text-[11px] text-gray-500 line-clamp-1">{t.description}</p>
                          </div>
                      ))}
                  </div>
              )}

              <button onClick={handleNext} disabled={!topic} className={`w-full py-5 md:py-6 rounded-2xl font-black text-white shadow-2xl hover:opacity-90 transition-all disabled:opacity-30 text-lg md:text-xl tracking-widest uppercase relative z-10 ${mode === 'viral' ? 'bg-gradient-to-r from-orange-600 to-red-600' : 'bg-gradient-to-r from-blue-600 to-primary'}`}>
                開始生成文案 <span className="text-sm font-normal opacity-70 ml-2">(5 點數)</span>
              </button>
          </div>
      </div>
  );

  // ... (Step 2 Render remains same, omitted for brevity but preserved in final output)
  return (
    <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 animate-fade-in pt-4 pb-20">
        <div className="space-y-6">
            <div className="glass-card p-6 md:p-8 rounded-3xl relative overflow-hidden">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="font-black text-gray-300 tracking-tighter uppercase text-sm">內容編輯器 ({mode === 'viral' ? '爆文模式' : '品牌模式'})</h3>
                    <button onClick={() => setStep(1)} className="text-[10px] font-bold text-red-400 hover:text-white transition-colors uppercase tracking-widest border border-red-500/30 px-2 py-1 rounded">← 重設主題</button>
                </div>

                <label className="text-[10px] text-gray-500 font-bold mb-2 block uppercase tracking-wider">貼文文案 (Caption)</label>
                <textarea value={draft.caption} onChange={e => setDraft({...draft, caption: e.target.value})} className="w-full h-[200px] p-6 text-white mb-6 resize-none outline-none custom-scrollbar leading-relaxed text-[15px] rounded-2xl" />

                {/* New Image Settings Logic */}
                <div className="mb-6 p-4 bg-black/30 rounded-xl border border-gray-700">
                    <label className="text-[10px] text-primary font-bold mb-2 block uppercase tracking-wider">選擇配圖風格 (Image Intent)</label>
                    <div className="flex gap-2 mb-4 overflow-x-auto pb-2">
                        {(['product_showcase', 'promotion', 'lifestyle', 'educational', 'festival'] as ImageIntent[]).map(intent => (
                            <button 
                                key={intent}
                                onClick={() => handleIntentChange(intent)}
                                className={`px-3 py-2 rounded-lg text-xs font-bold whitespace-nowrap border transition-all ${imageIntent === intent ? 'bg-primary text-black border-primary' : 'bg-transparent text-gray-400 border-gray-600 hover:border-gray-400'}`}
                            >
                                {intent === 'product_showcase' ? '📦 產品特寫' : intent === 'promotion' ? '🏷️ 促銷 Banner' : intent === 'lifestyle' ? '🏖️ 情境生活' : intent === 'educational' ? '📚 知識圖卡' : '🎉 節慶賀圖'}
                            </button>
                        ))}
                    </div>

                    {/* TEXT MODE SELECTION */}
                    <div className="mb-4 pt-3 border-t border-gray-700">
                        <label className="text-[10px] text-gray-400 font-bold mb-2 block uppercase tracking-wider">文字渲染模式 (Text Mode)</label>
                        <div className="flex bg-black/40 rounded-lg p-1 mb-4 border border-gray-600">
                            <button 
                                onClick={() => setRenderMode('plain')}
                                className={`flex-1 py-2 rounded text-xs font-bold transition-all ${renderMode === 'plain' ? 'bg-gray-700 text-white shadow' : 'text-gray-500 hover:text-gray-300'}`}
                            >
                                純淨無字
                            </button>
                            <button 
                                onClick={() => setRenderMode('smart_layout')}
                                className={`flex-1 py-2 rounded text-xs font-bold transition-all ${renderMode === 'smart_layout' ? 'bg-yellow-600 text-white shadow' : 'text-gray-500 hover:text-gray-300'}`}
                            >
                                ⚡ 智慧排版 (推薦)
                            </button>
                            <button 
                                onClick={() => setRenderMode('ai_text')}
                                className={`flex-1 py-2 rounded text-xs font-bold transition-all ${renderMode === 'ai_text' ? 'bg-red-900/50 text-red-300 border border-red-800' : 'text-gray-500 hover:text-gray-300'}`}
                            >
                                AI 生成 (實驗性)
                            </button>
                        </div>

                        {renderMode === 'smart_layout' && (
                            <div className="bg-yellow-900/10 border border-yellow-600/30 p-4 rounded-xl animate-fade-in space-y-3">
                                <p className="text-[10px] text-yellow-200/80 mb-1 flex items-center gap-2">
                                    <span className="text-lg">✨</span> 系統將自動在圖片底部合成電影感字幕。
                                </p>
                                <div>
                                    <label className="text-[10px] text-gray-400 block mb-1">主標題</label>
                                    <input 
                                        value={layoutTitle}
                                        onChange={e => setLayoutTitle(e.target.value)}
                                        className="w-full bg-black/40 border border-yellow-600/30 rounded p-2 text-white text-sm focus:border-yellow-500 outline-none"
                                        placeholder="例如：泰國曼谷五日遊"
                                    />
                                </div>
                                <div>
                                    <label className="text-[10px] text-gray-400 block mb-1">副標題 / 價格</label>
                                    <input 
                                        value={layoutSubtitle}
                                        onChange={e => setLayoutSubtitle(e.target.value)}
                                        className="w-full bg-black/40 border border-yellow-600/30 rounded p-2 text-yellow-400 font-bold text-sm focus:border-yellow-500 outline-none"
                                        placeholder="例如：$29,900 起"
                                    />
                                </div>
                            </div>
                        )}

                        {renderMode === 'ai_text' && (
                            <div className="bg-red-900/10 border border-red-500/50 p-4 rounded-xl animate-fade-in">
                                <p className="text-xs text-red-300 font-bold mb-2 flex items-center gap-2">
                                    <span>⚠️</span> 警告：AI 直接生成
                                </p>
                                <p className="text-[10px] text-red-200/80 mb-3 leading-relaxed">
                                    此模式由 DALL-E 3 直接嘗試在圖片中「畫」出文字。
                                    <br/>
                                    <strong>即便在最強模型下，中文字仍有極高機率變成亂碼。建議使用「智慧排版」模式。</strong>
                                </p>
                                <input 
                                    value={customImageText}
                                    onChange={e => setCustomImageText(e.target.value)}
                                    placeholder="請輸入欲顯示的文字 (例如: NT$18,900)"
                                    className="w-full bg-black/40 border border-red-500/30 rounded-lg p-3 text-white text-sm focus:border-red-500 outline-none placeholder-gray-500"
                                />
                            </div>
                        )}
                    </div>

                    <label className="flex justify-between items-center text-[10px] text-gray-500 font-bold mb-2 uppercase tracking-wider">
                        <span>視覺提示詞 (AI Prompt)</span>
                        <button onClick={() => setDraft(prev => ({...prev, imagePrompt: ''}))} className="text-red-400 hover:text-white transition-colors text-[9px] border border-red-500/30 px-1 rounded">清空以重新生成</button>
                    </label>
                    <textarea 
                        value={draft.imagePrompt} 
                        onChange={e => setDraft({...draft, imagePrompt: e.target.value})} 
                        className="w-full h-16 p-3 text-gray-300 text-xs outline-none resize-none leading-relaxed rounded-xl border border-gray-700 bg-black/20 focus:border-primary/50 transition-colors" 
                        placeholder={mediaUrl ? "您可手動修改 Prompt 並點擊重新繪製..." : "點擊「生成圖片」後，AI 將自動根據文案與風格填寫此處..."} 
                    />
                </div>

                <div className="space-y-4">
                    <button 
                        onClick={handleGenMedia} 
                        disabled={isGeneratingMedia}
                        className={`w-full py-5 rounded-2xl font-black text-white shadow-lg transition-all flex items-center justify-center gap-3 tracking-widest uppercase border border-white/10 disabled:opacity-50 disabled:cursor-not-allowed ${mediaUrl ? 'bg-black/40 hover:bg-black/60' : 'bg-gradient-to-r from-indigo-600 to-purple-600 hover:brightness-110'}`}
                    >
                        {isGeneratingMedia ? (
                            <>
                                <div className="loader w-4 h-4 border-t-white"></div>
                                繪製中...
                            </>
                        ) : mediaUrl ? (
                            <>重新繪製 (依據當前 Prompt) <span className="text-[10px] font-black bg-white/20 px-2 py-0.5 rounded-full">5 點數</span></>
                        ) : (
                            <>生成商業設計圖 (Ideogram/Imagen) <span className="text-[10px] font-black bg-white/20 px-2 py-0.5 rounded-full">8 點數</span></>
                        )}
                    </button>
                </div>
            </div>
        </div>

        <div className="space-y-6">
            <div className="glass-card p-6 md:p-8 rounded-3xl flex flex-col min-h-[600px] relative">
                <h3 className="font-black text-gray-300 tracking-tighter uppercase text-sm mb-6">預覽效果</h3>

                <div className="bg-white rounded-[2rem] overflow-hidden flex-1 border-8 border-gray-900 shadow-2xl flex flex-col relative mx-auto w-full max-w-sm">
                    <div className="bg-white text-black text-[10px] font-bold p-3 flex justify-between px-6"><span>9:41</span><span>📶 🔋</span></div>
                    <div className="p-4 border-b border-gray-100 flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-yellow-400 to-red-500 flex items-center justify-center text-white text-xs font-bold">B</div>
                        <div className="space-y-0.5"><div className="h-2 w-20 bg-gray-200 rounded"></div><div className="h-1.5 w-12 bg-gray-100 rounded"></div></div>
                    </div>
                    <div className="p-4 overflow-y-auto max-h-[400px] custom-scrollbar flex-1 bg-white">
                        <p className="text-black text-[14px] whitespace-pre-wrap mb-4 leading-relaxed font-sans">{draft.caption}</p>
                        {mediaUrl && <img src={mediaUrl} className="w-full h-auto rounded-xl shadow-sm border border-gray-100 animate-fade-in" />}
                        {!mediaUrl && (
                            <div className="w-full aspect-square bg-gray-50 rounded-2xl border-2 border-dashed border-gray-200 flex flex-col items-center justify-center text-gray-300 gap-2">
                                <span className="text-2xl opacity-50">🖼️</span>
                                <span className="text-[10px] font-bold uppercase tracking-widest text-center px-4">
                                    {draft.caption ? "請選擇左側風格並點擊生成圖片" : "等待文案生成..."}
                                </span>
                            </div>
                        )}
                        <div className="flex gap-4 mt-4 text-gray-400">
                             <div className="w-5 h-5 bg-gray-100 rounded-full"></div>
                             <div className="w-5 h-5 bg-gray-100 rounded-full"></div>
                             <div className="w-5 h-5 bg-gray-100 rounded-full ml-auto"></div>
                        </div>
                    </div>
                </div>

                {publishResult ? (
                    <div className={`mt-8 p-5 rounded-2xl text-center font-bold border transition-all ${publishResult.success ? 'bg-green-500/20 text-green-400 border-green-500/50' : 'bg-red-500/20 text-red-400 border-red-500/50'}`}>
                        <div className="text-[15px] mb-1">{publishResult.msg}</div>
                        <button onClick={() => setPublishResult(null)} className="text-[10px] uppercase font-black tracking-widest text-white/50 hover:text-white transition-colors underline underline-offset-4">返回編輯</button>
                    </div>
                ) : (
                    <div className="mt-8 space-y-4">
                        <div className="bg-black/40 p-4 rounded-xl border border-white/5 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                            <div className="flex-1 w-full">
                                <label className="block text-[9px] text-gray-500 font-black uppercase tracking-[0.2em] mb-1">FB 排程發佈 (選填)</label>
                                <input type="datetime-local" value={scheduleDate} onChange={e => setScheduleDate(e.target.value)} className="w-full bg-transparent text-white outline-none text-sm font-bold p-0 border-none" />
                            </div>
                            <div className={`px-3 py-1 rounded text-[10px] font-black uppercase tracking-widest border ${isLimitReached ? 'text-red-400 border-red-900/50' : 'text-primary border-primary/20'}`}>
                                {scheduledPostsCount}/{limit} 席位
                            </div>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => handleFinalize(true)} disabled={isLimitReached} className={`flex-1 py-4 rounded-xl font-black transition-all border uppercase tracking-widest text-xs ${isLimitReached ? 'border-gray-800 text-gray-700 cursor-not-allowed' : 'border-gray-600 text-gray-400 hover:border-white hover:text-white'}`}>
                                {isLimitReached ? '已滿' : '排程發佈 (FB API)'}
                            </button>
                            <button onClick={() => handleFinalize(false)} className="flex-1 bg-white text-black py-4 rounded-xl font-black shadow-[0_0_20px_rgba(255,255,255,0.2)] hover:bg-gray-200 transition-all transform active:scale-95 text-xs uppercase tracking-widest">
                                立即發佈
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BrandSettings, ThreadsAccount, UserProfile } from '../../types';
import AccountManager from './AccountManager';
import InteractionManager from './InteractionManager';
import ContentGenerator from './ContentGenerator';
import DigitalDNALab from './DigitalDNALab';
import OpportunityScout from './OpportunityScout';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onSaveSettings: (settings: BrandSettings) => void;
  onQuotaUpdate: () => void;
  initialTopic?: string; // New Prop
}

const ThreadsNurturePanel: React.FC<Props> = ({ settings, user, onSaveSettings, onQuotaUpdate, initialTopic }) => {
  const [activeTab, setActiveTab] = useState<'accounts' | 'interaction' | 'generator' | 'dna_lab' | 'scout'>('accounts');
  const [accounts, setAccounts] = useState<ThreadsAccount[]>(settings.threadsAccounts || []);

  // Sync state when external settings change
  useEffect(() => {
      if (JSON.stringify(settings.threadsAccounts) !== JSON.stringify(accounts)) {
          setAccounts(settings.threadsAccounts || []);
      }
  }, [settings.threadsAccounts]);

  // Handle Initial Topic from Stock Market
  useEffect(() => {
      if (initialTopic) {
          setActiveTab('generator');
      }
  }, [initialTopic]);

  const handleAccountsChange = (newAccounts: ThreadsAccount[]) => {
      setAccounts(newAccounts);
      onSaveSettings({ ...settings, threadsAccounts: newAccounts });
  };

  return (
    <div className="max-w-6xl mx-auto p-4 animate-fade-in pb-20">
      <div className="flex justify-between items-center mb-6">
          <h2 className="text-3xl font-bold text-white">Threads 進階功能</h2>
          <div className="text-xs text-gray-400">多帳號管理 • 風格學習 • 商機開發</div>
      </div>

      <div className="flex border-b border-gray-700 mb-6 overflow-x-auto custom-scrollbar">
        <button onClick={() => setActiveTab('accounts')} className={`px-6 py-3 font-bold whitespace-nowrap transition-colors ${activeTab === 'accounts' ? 'text-white border-b-2' : 'text-gray-500 hover:text-gray-300'}`}>帳號管理</button>
        <button onClick={() => setActiveTab('scout')} className={`px-6 py-3 font-bold whitespace-nowrap transition-colors ${activeTab === 'scout' ? 'text-yellow-400 border-b-2 border-yellow-400' : 'text-gray-500 hover:text-gray-300'}`}>商機開發</button>
        <button onClick={() => setActiveTab('interaction')} className={`px-6 py-3 font-bold whitespace-nowrap transition-colors ${activeTab === 'interaction' ? 'text-pink-400 border-b-2 border-pink-400' : 'text-gray-500 hover:text-gray-300'}`}>留言互動</button>
        <button onClick={() => setActiveTab('generator')} className={`px-6 py-3 font-bold whitespace-nowrap transition-colors ${activeTab === 'generator' ? 'text-white border-b-2' : 'text-gray-500 hover:text-gray-300'}`}>內容生成</button>
        <button onClick={() => setActiveTab('dna_lab')} className={`px-6 py-3 font-bold whitespace-nowrap transition-colors ${activeTab === 'dna_lab' ? 'text-purple-400 border-b-2 border-purple-400' : 'text-gray-500 hover:text-gray-300'}`}>基因實驗室</button>
      </div>

      {activeTab === 'accounts' && (
          <AccountManager 
              accounts={accounts} 
              setAccounts={handleAccountsChange}
              settings={settings}
              onSaveSettings={onSaveSettings}
              user={user} 
              onQuotaUpdate={onQuotaUpdate} 
          />
      )}

      {activeTab === 'scout' && (
          <OpportunityScout 
              accounts={accounts}
              user={user}
              onQuotaUpdate={onQuotaUpdate}
          />
      )}

      {activeTab === 'interaction' && (
          <InteractionManager 
              accounts={accounts} 
              user={user} 
              onQuotaUpdate={onQuotaUpdate} 
          />
      )}

      {activeTab === 'generator' && (
          <ContentGenerator 
              settings={settings} 
              accounts={accounts} 
              user={user} 
              onQuotaUpdate={onQuotaUpdate} 
              initialTopic={initialTopic}
          />
      )}

      {activeTab === 'dna_lab' && (
          <DigitalDNALab 
              accounts={accounts}
              user={user}
              onQuotaUpdate={onQuotaUpdate}
          />
      )}
    </div>
  );
};

export default ThreadsNurturePanel;

import React, { useState, useEffect } from 'react';
import { BrandSettings, ThreadsAccount, UserProfile, TrendingTopic } from '../../types';
import { getTrendingTopics, generateThreadsBatch, fetchNewsImageFromUrl } from '../../services/geminiService';
import { publishThreadsPost } from '../../services/threadsService';
import { checkAndUseQuota } from '../../services/authService';
import { getThreadsSystemInstruction } from '../../services/promptTemplates';
import { LoadingOverlay, ImagePreview, generateStockUrl } from './ThreadsCommon';

type ImageSourceType = 'ai' | 'stock' | 'news' | 'upload' | 'none';

interface GeneratedPost {
  id: string;
  topic: string; 
  caption: string;
  imagePrompt: string;
  imageQuery: string;
  imageUrl?: string; 
  newsImageUrl?: string; 
  uploadedImageBase64?: string;
  targetAccountId?: string;
  status: 'idle' | 'publishing' | 'done' | 'failed';
  log?: string;
  imageSourceType: ImageSourceType;
  paidForGeneration?: boolean; 
}

interface Props {
    settings: BrandSettings;
    accounts: ThreadsAccount[];
    user: UserProfile | null;
    onQuotaUpdate: () => void;
    initialTopic?: string; // New Prop
}

const ContentGenerator: React.FC<Props> = ({ settings, accounts, user, onQuotaUpdate, initialTopic }) => {
    // State
    const [genStep, setGenStep] = useState<1 | 2>(1);
    const [manualTopic, setManualTopic] = useState('');
    const [selectedTopics, setSelectedTopics] = useState<string[]>([]);
    const [genCount, setGenCount] = useState<1 | 2 | 3>(1);
    const [preSelectedImageMode, setPreSelectedImageMode] = useState<ImageSourceType>('none');
    const [selectedGenAccountId, setSelectedGenAccountId] = useState<string>(''); 
    const [generatedPosts, setGeneratedPosts] = useState<GeneratedPost[]>([]);
    const [isGenerating, setIsGenerating] = useState(false);
    const [isRegeneratingImage, setIsRegeneratingImage] = useState<string | null>(null);
    const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
    const [loadingTrends, setLoadingTrends] = useState(false);
    const [trendError, setTrendError] = useState('');

    // Effects
    useEffect(() => {
        if (accounts.length > 0) {
            const currentSelectionExists = accounts.some(a => a.id === selectedGenAccountId);
            if (!selectedGenAccountId || !currentSelectionExists) {
                setSelectedGenAccountId(accounts[0].id);
            }
        }
    }, [accounts]);

    // Handle Initial Topic from Stock Market
    useEffect(() => {
        if (initialTopic) {
            setSelectedTopics([initialTopic]);
            setManualTopic(initialTopic); // Also set manual so it persists visually if deselected
            setGenStep(2); // Jump directly to Step 2
        }
    }, [initialTopic]);

    const loadTrends = async (overrideKeyword?: string) => {
        if (!user) return alert("請先登入");

        // [BILLING] Trend Search: 3 Points
        const COST = 3; 
        const allowed = await checkAndUseQuota(user.user_id, COST, 'TREND_SEARCH');
        if (!allowed) return; 

        onQuotaUpdate();
        setLoadingTrends(true);
        setTrendError('');
        setTrendingTopics([]);

        try {
            const query = overrideKeyword || manualTopic || settings.industry || '台灣熱門時事';
            const trends = await getTrendingTopics(query);
            if (trends.length === 0) setTrendError("目前找不到相關新聞，請嘗試手動輸入其他話題。");
            setTrendingTopics(trends);
        } catch (e: any) {
            console.warn("Trend load error", e);
            setTrendError("無法載入即時趨勢，請檢查網路或稍後再試。");
        } finally {
            setLoadingTrends(false);
        }
    };

    const selectTopic = (title: string) => {
        if (selectedTopics.includes(title)) setSelectedTopics([]);
        else { setSelectedTopics([title]); setManualTopic(''); }
    };

    const handleManualTopicChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setManualTopic(e.target.value);
        if (e.target.value) setSelectedTopics([]);
    };

    const proceedToGenerateUI = () => {
        if (selectedTopics.length === 0 && !manualTopic) return alert("請先選擇或輸入一個話題");
        setGenStep(2);
    };

    const calculateCost = (count: number, mode: ImageSourceType) => {
        const baseCost = 2; // Text generation base
        let extraCost = 0;
        // [BILLING] AI Image (First): 6 Points Total -> Base 2 + Extra 4
        if (mode === 'ai') extraCost = 4; 
        else if (mode === 'news') extraCost = 1;
        else if (mode === 'stock') extraCost = 1;
        return (baseCost + extraCost) * count;
    };

    const handleGenerateBatch = async () => {
        if (!user) return alert("請先登入");
        const topicSource = selectedTopics.length > 0 ? selectedTopics[0] : manualTopic;
        if (!topicSource) return alert("無效話題");

        const targetAccount = accounts.find(a => a.id === selectedGenAccountId);
        if (!targetAccount) return alert("錯誤：請先在上方選單選擇要發文的帳號");

        const totalCost = calculateCost(genCount, preSelectedImageMode);
        if (!confirm(`確定為帳號「${targetAccount.username}」生成 ${genCount} 篇貼文？\n\n消耗：${totalCost} 點配額`)) return;

        const allowed = await checkAndUseQuota(user.user_id, totalCost, 'THREADS_BATCH_GEN', { count: genCount, mode: preSelectedImageMode });
        if (!allowed) return; 
        onQuotaUpdate();

        setIsGenerating(true);
        setGeneratedPosts([]);

        try {
            const instruction = getThreadsSystemInstruction(
                targetAccount.accountType || 'personal',
                targetAccount.styleGuide,
                targetAccount.safetyFilter
            );

            const results = await generateThreadsBatch(topicSource, genCount, settings, [instruction]);
            const sourceTopicData = trendingTopics.find(t => t.title === topicSource);
            const initialNewsImg = sourceTopicData?.imageUrl;
            const newsUrl = sourceTopicData?.url;

            const newPosts: GeneratedPost[] = await Promise.all(results.map(async (r, i) => {
                let finalMode = preSelectedImageMode;
                let finalImageUrl = undefined;
                let errorLog = undefined;
                const uniqueSeed = Date.now().toString() + i;

                if (finalMode === 'ai') {
                    const encoded = encodeURIComponent(r.imagePrompt);
                    finalImageUrl = `https://image.pollinations.ai/prompt/${encoded}?n=${uniqueSeed}&model=flux`;
                } else if (finalMode === 'stock') {
                    finalImageUrl = generateStockUrl(r.imageQuery || r.imagePrompt, uniqueSeed);
                } else if (finalMode === 'news') {
                    if (initialNewsImg) finalImageUrl = initialNewsImg;
                    else if (newsUrl) {
                        const ogImg = await fetchNewsImageFromUrl(newsUrl);
                        if (ogImg) finalImageUrl = ogImg;
                    }
                    if (!finalImageUrl) {
                        try {
                           finalImageUrl = generateStockUrl(`News photo about ${topicSource}, realistic, journalism style`, uniqueSeed);
                        } catch (e) { finalMode = 'none'; errorLog = '無法取得新聞圖片'; }
                    }
                }

                return {
                    id: Date.now() + '_' + i,
                    topic: topicSource,
                    caption: r.caption,
                    imagePrompt: r.imagePrompt,
                    imageQuery: r.imageQuery,
                    newsImageUrl: finalMode === 'news' ? finalImageUrl : undefined,
                    imageUrl: (finalMode === 'ai' || finalMode === 'stock' || finalMode === 'news') ? finalImageUrl : undefined,
                    imageSourceType: finalMode,
                    log: errorLog,
                    status: 'idle',
                    targetAccountId: targetAccount.id
                };
            }));

            setGeneratedPosts(newPosts);
        } catch (e: any) {
            alert(`生成失敗: ${e.message}`);
        } finally {
            setIsGenerating(false);
        }
    };

    const getPreviewUrl = (post: GeneratedPost) => {
        if (post.imageSourceType === 'upload' && post.uploadedImageBase64) return post.uploadedImageBase64;
        if (post.imageSourceType === 'news' && post.newsImageUrl) return post.newsImageUrl;
        if (post.imageUrl) return post.imageUrl;
        return '';
    };

    const handleImageModeChange = async (post: GeneratedPost, newMode: ImageSourceType) => {
        if (newMode === 'stock' || newMode === 'ai') { 
            if (!user) return alert("請先登入");

            // [BILLING] Threads Image Regen: 4 Points
            const COST = 4; 
            const allowed = await checkAndUseQuota(user.user_id, COST, 'THREADS_REGEN_IMAGE');
            if (!allowed) return; 
            onQuotaUpdate();

            setIsRegeneratingImage(post.id);
            const newSeed = Date.now().toString() + Math.floor(Math.random() * 9999);
            const visualSubject = post.imageQuery || post.topic; 
            const newUrl = generateStockUrl(visualSubject, newSeed);

            setTimeout(() => {
                setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, imageSourceType: newMode, imageUrl: newUrl } : p));
                setIsRegeneratingImage(null);
            }, 500); 
        } else {
            setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, imageSourceType: newMode } : p));
        }
    };

    const handlePublish = async (post: GeneratedPost) => {
        if (!post.targetAccountId) return alert("錯誤：未指定發佈帳號");
        const acc = accounts.find(a => a.id === post.targetAccountId);
        if (!acc) return alert("錯誤：找不到對應的帳號資料，請檢查帳號是否已被移除。");
        if (!post.caption) return alert("內容為空，無法發佈");

        setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'publishing', log: '發佈中...' } : p));
        try {
            const imgUrl = post.imageSourceType === 'none' ? undefined : getPreviewUrl(post);
            const res = await publishThreadsPost(acc, post.caption, imgUrl);
            if (res.success) {
                setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'done', log: '發佈成功！' } : p));
            } else {
                setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'failed', log: `發佈失敗: ${res.error}` } : p));
                alert(`發佈失敗: ${res.error}`);
            }
        } catch (e: any) {
            setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'failed', log: `系統錯誤: ${e.message}` } : p));
        }
    };

    if (loadingTrends) return <LoadingOverlay message="正在搜尋熱門話題" detail="AI 正在分析全網新聞與社群趨勢..." />;
    if (isGenerating) return <LoadingOverlay message="AI 正在量產 Threads 貼文" detail={`正在模擬 ${genCount} 篇不同語氣的真實貼文，並準備圖片中...`} />;

    return (
        <div className="space-y-6">
            {genStep === 1 && (
                <div className="bg-card p-6 rounded-xl border border-gray-700">
                     <h3 className="text-xl font-bold text-white mb-4">步驟 1: 選擇話題</h3>
                     <div className="mb-6 p-4 bg-dark/50 rounded-lg border border-gray-600">
                         <label className="block text-xs text-gray-400 mb-2 font-bold uppercase tracking-wider">第一步：設定或搜尋話題</label>
                         <div className="flex flex-col md:flex-row gap-2">
                             <input 
                                 value={manualTopic} 
                                 onChange={handleManualTopicChange} 
                                 className="flex-1 bg-dark border border-gray-600 rounded p-3 text-white placeholder-gray-500 focus:border-primary outline-none transition-colors" 
                                 placeholder="輸入關鍵字 (例如: AI, 美食, 房地產)..." 
                             />
                             <button 
                                 onClick={() => loadTrends()} 
                                 className="bg-indigo-600 hover:bg-indigo-500 text-white px-6 py-3 md:py-0 rounded font-bold transition-colors whitespace-nowrap flex items-center justify-center gap-2"
                             >
                                 搜尋趨勢 (3點)
                             </button>
                         </div>
                         <p className="text-[10px] text-gray-500 mt-2">提示：輸入關鍵字後點擊「搜尋」，AI 將為您挖掘該領域的最新熱門新聞。</p>
                     </div>
                     <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mb-4 max-h-[60vh] overflow-y-auto custom-scrollbar p-1">
                          <div onClick={() => loadTrends(settings.industry)} className="flex flex-col items-center justify-center bg-gray-800/50 border border-gray-600 hover:border-gray-400 rounded-lg p-6 cursor-pointer min-h-[160px] text-center shadow-lg transition-transform active:scale-95 group">
                              <span className="text-lg font-bold text-gray-300 group-hover:text-white">挖掘綜合熱門靈感</span>
                              <span className="text-[10px] bg-primary/20 text-primary px-2 py-0.5 rounded mt-2 font-bold tracking-wider">3 點數</span>
                              <p className="text-xs text-gray-500 mt-2">查看 {settings.industry || '台灣'} 目前最紅的話題</p>
                          </div>
                          {trendingTopics.map((t, i) => (
                              <div key={i} onClick={() => selectTopic(t.title)} className={`flex flex-col justify-between p-4 rounded-lg border cursor-pointer min-h-[160px] transition-all relative overflow-hidden ${selectedTopics.includes(t.title) ? 'bg-primary/20 border-primary ring-2 ring-primary' : 'bg-dark border-gray-700 hover:border-gray-500'}`}>
                                  {t.imageUrl && <div className="absolute inset-0 opacity-10 bg-cover bg-center z-0" style={{backgroundImage: `url(${t.imageUrl})`}}></div>}
                                  <div className="relative z-10">
                                      <h4 className="font-bold text-white text-base line-clamp-2 mb-2 leading-tight">{t.title}</h4>
                                      <p className="text-xs text-gray-400 line-clamp-3 leading-relaxed">{t.description || "點擊查看詳情，AI 將自動延伸話題..."}</p>
                                  </div>
                                  <div className="relative z-10 mt-2 text-[10px] text-gray-500 flex justify-between items-center">
                                      <span>來源: {t.url ? new URL(t.url).hostname.replace('www.', '') : 'News'}</span>
                                      {selectedTopics.includes(t.title) && <span className="text-primary font-bold">✓ 已選擇</span>}
                                  </div>
                              </div>
                          ))}
                     </div>
                     <div className="mt-6 flex justify-end"><button onClick={proceedToGenerateUI} className="bg-primary hover:bg-blue-600 text-white px-8 py-3 rounded font-bold shadow-lg w-full md:w-auto">下一步</button></div>
                </div>
            )}

            {genStep === 2 && (
                <div className="space-y-6">
                    <div className="bg-card p-6 rounded-xl border border-gray-700">
                         <div className="flex justify-between items-center mb-6">
                             <h3 className="text-xl font-bold text-white">步驟 2: 生成與發佈</h3>
                             <button onClick={() => setGenStep(1)} className="text-sm text-gray-400 hover:text-white border border-gray-600 px-3 py-1 rounded hover:bg-gray-700 transition-colors">↩ 返回選題</button>
                         </div>
                         <div className="mb-6 bg-blue-900/20 p-4 rounded border border-blue-800">
                             <label className="block text-sm text-blue-300 font-bold mb-2">1. 選擇發文帳號 (決定語氣與人設) *</label>
                             <select value={selectedGenAccountId} onChange={(e) => setSelectedGenAccountId(e.target.value)} className="w-full bg-dark border border-blue-500 rounded p-3 text-white">
                                 {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.username} ({acc.accountType === 'brand' ? '品牌' : '個人'})</option>)}
                              </select>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                             <div className="bg-dark/50 p-4 rounded border border-gray-600"><label className="block text-sm text-gray-400 mb-2">當前話題</label><div className="font-bold text-xl text-white">{selectedTopics[0] || manualTopic}</div></div>
                             <div className="space-y-4">
                                 <div><label className="block text-sm text-gray-400 mb-1">數量</label><div className="flex gap-2">{[1,2,3].map(n => <button key={n} onClick={() => setGenCount(n as any)} className={`flex-1 py-2 rounded border ${genCount === n ? 'bg-white text-black' : 'border-gray-600'}`}>{n}</button>)}</div></div>
                                 <div><label className="block text-sm text-gray-400 mb-1">圖片</label><select value={preSelectedImageMode} onChange={(e) => setPreSelectedImageMode(e.target.value as any)} className="w-full bg-dark border border-gray-600 rounded p-2 text-white"><option value="none">無圖片</option><option value="stock">擬真圖庫</option><option value="ai">AI繪圖 (推薦)</option></select></div>
                             </div>
                         </div>
                         <button onClick={handleGenerateBatch} disabled={!selectedGenAccountId} className="w-full bg-gradient-to-r from-pink-600 to-purple-600 text-white py-4 rounded-xl font-bold text-lg shadow-lg">生成貼文</button>
                    </div>

                    {generatedPosts.length > 0 && (
                        <div className="space-y-8">
                            {generatedPosts.map((post) => (
                                <div key={post.id} className="bg-card rounded-xl border border-gray-700 overflow-hidden flex flex-col md:flex-row">
                                    <div className="w-full md:w-1/3 bg-black flex items-center justify-center relative min-h-[300px]">
                                        {getPreviewUrl(post) ? (
                                            <ImagePreview src={getPreviewUrl(post)} alt="Generated Content" />
                                        ) : <span className="text-gray-500">無圖片</span>}
                                        <div className="absolute bottom-2 left-2 flex gap-2">
                                            <button onClick={() => handleImageModeChange(post, 'stock')} disabled={isRegeneratingImage === post.id} className="text-xs bg-gray-700 hover:bg-gray-600 text-white px-3 py-2 rounded shadow-lg font-bold border border-gray-500 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-1">
                                                {isRegeneratingImage === post.id ? (<><div className="loader w-3 h-3 border-2 border-t-white"></div>生成中...</>) : '隨機換圖 (4點)'}
                                            </button>
                                        </div>
                                    </div>
                                    <div className="flex-1 p-6 flex flex-col">
                                        <textarea value={post.caption} onChange={(e) => setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, caption: e.target.value } : p))} className="w-full flex-1 bg-dark border border-gray-600 rounded p-3 text-white mb-4 resize-none" />
                                        <div className="flex justify-between items-center">
                                            <span className={`text-xs font-bold ${post.status === 'done' ? 'text-green-400' : post.status === 'failed' ? 'text-red-400' : 'text-gray-500'}`}>{post.log || (post.status === 'idle' ? '準備就緒' : '')}</span>
                                            <button onClick={() => handlePublish(post)} disabled={post.status === 'publishing' || post.status === 'done'} className={`px-6 py-3 rounded font-bold transition-all ${post.status === 'done' ? 'bg-green-600 text-white cursor-default' : 'bg-white text-black hover:bg-gray-200'}`}>
                                                {post.status === 'publishing' ? '發佈中...' : post.status === 'done' ? '已發佈' : '立即發佈'}
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

export default ContentGenerator;

import React, { useState, useEffect } from 'react';
import { BrandSettings, ThreadsAccount, UserProfile } from '../types';
import AccountManager from './threads/AccountManager';
import InteractionManager from './threads/InteractionManager';
import ContentGenerator from './threads/ContentGenerator';
import DigitalDNALab from './threads/DigitalDNALab';
import OpportunityScout from './threads/OpportunityScout'; // New Component

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onSaveSettings: (settings: BrandSettings) => void;
  onQuotaUpdate: () => void;
  initialTopic?: string; // New Prop
}

const ThreadsNurturePanel: React.FC<Props> = ({ settings, user, onSaveSettings, onQuotaUpdate, initialTopic }) => {
  const [activeTab, setActiveTab] = useState<'accounts' | 'interaction' | 'generator' | 'dna_lab' | 'scout'>('accounts');
  const [accounts, setAccounts] = useState<ThreadsAccount[]>(settings.threadsAccounts || []);

  // Sync state when external settings change (e.g. from OAuth callback in App.tsx)
  useEffect(() => {
      if (JSON.stringify(settings.threadsAccounts) !== JSON.stringify(accounts)) {
          setAccounts(settings.threadsAccounts || []);
      }
  }, [settings.threadsAccounts]);

  // Handle Initial Topic from Stock Market
  useEffect(() => {
      if (initialTopic) {
          setActiveTab('generator');
      }
  }, [initialTopic]);

  // Update parent settings whenever local accounts change
  const handleAccountsChange = (newAccounts: ThreadsAccount[]) => {
      setAccounts(newAccounts);
      onSaveSettings({ ...settings, threadsAccounts: newAccounts });
  };

  return (
    <div className="max-w-6xl mx-auto p-4 animate-fade-in pb-20">
      <div className="flex justify-between items-center mb-6">
          <h2 className="text-3xl font-bold text-white">Threads 進階功能</h2>
          <div className="text-xs text-gray-400">多帳號管理 • 風格學習 • 商機開發</div>
      </div>

      <div className="flex border-b border-gray-700 mb-6 overflow-x-auto custom-scrollbar">
        <button onClick={() => setActiveTab('accounts')} className={`px-6 py-3 font-bold whitespace-nowrap transition-colors ${activeTab === 'accounts' ? 'text-white border-b-2' : 'text-gray-500 hover:text-gray-300'}`}>帳號管理</button>
        <button onClick={() => setActiveTab('scout')} className={`px-6 py-3 font-bold whitespace-nowrap transition-colors ${activeTab === 'scout' ? 'text-yellow-400 border-b-2 border-yellow-400' : 'text-gray-500 hover:text-gray-300'}`}>💎 商機開發</button>
        <button onClick={() => setActiveTab('interaction')} className={`px-6 py-3 font-bold whitespace-nowrap transition-colors ${activeTab === 'interaction' ? 'text-pink-400 border-b-2 border-pink-400' : 'text-gray-500 hover:text-gray-300'}`}>留言互動</button>
        <button onClick={() => setActiveTab('generator')} className={`px-6 py-3 font-bold whitespace-nowrap transition-colors ${activeTab === 'generator' ? 'text-white border-b-2' : 'text-gray-500 hover:text-gray-300'}`}>內容生成</button>
        <button onClick={() => setActiveTab('dna_lab')} className={`px-6 py-3 font-bold whitespace-nowrap transition-colors ${activeTab === 'dna_lab' ? 'text-purple-400 border-b-2 border-purple-400' : 'text-gray-500 hover:text-gray-300'}`}>🧪 基因實驗室</button>
      </div>

      {activeTab === 'accounts' && (
          <AccountManager 
              accounts={accounts} 
              setAccounts={handleAccountsChange}
              settings={settings}
              onSaveSettings={onSaveSettings}
              user={user} 
              onQuotaUpdate={onQuotaUpdate} 
          />
      )}

      {activeTab === 'scout' && (
          <OpportunityScout 
              accounts={accounts}
              user={user}
              onQuotaUpdate={onQuotaUpdate}
          />
      )}

      {activeTab === 'interaction' && (
          <InteractionManager 
              accounts={accounts} 
              user={user} 
              onQuotaUpdate={onQuotaUpdate} 
          />
      )}

      {activeTab === 'generator' && (
          <ContentGenerator 
              settings={settings} 
              accounts={accounts} 
              user={user} 
              onQuotaUpdate={onQuotaUpdate} 
              initialTopic={initialTopic}
          />
      )}

      {activeTab === 'dna_lab' && (
          <DigitalDNALab 
              accounts={accounts}
              user={user}
              onQuotaUpdate={onQuotaUpdate}
          />
      )}
    </div>
  );
};

export default ThreadsNurturePanel;

import React, { useState, useEffect } from 'react';
import { BrandSettings, ThreadsAccount, UserProfile, TrendingTopic } from '../../types';
import { getTrendingTopics, generateThreadsBatch, fetchNewsImageFromUrl } from '../../services/geminiService';
import { publishThreadsPost } from '../../services/threadsService';
import { checkAndUseQuota } from '../../services/authService';
import { getThreadsSystemInstruction } from '../../services/promptTemplates';
import { LoadingOverlay, ImagePreview, generateStockUrl } from './ThreadsCommon';

type ImageSourceType = 'ai' | 'stock' | 'news' | 'upload' | 'none';

interface GeneratedPost {
  id: string;
  topic: string; 
  caption: string;
  imagePrompt: string;
  imageQuery: string;
  imageUrl?: string; 
  newsImageUrl?: string; 
  uploadedImageBase64?: string;
  targetAccountId?: string;
  status: 'idle' | 'publishing' | 'done' | 'failed';
  log?: string;
  imageSourceType: ImageSourceType;
  paidForGeneration?: boolean; 
}

interface Props {
    settings: BrandSettings;
    accounts: ThreadsAccount[];
    user: UserProfile | null;
    onQuotaUpdate: () => void;
    initialTopic?: string; // New Prop
}

const ContentGenerator: React.FC<Props> = ({ settings, accounts, user, onQuotaUpdate, initialTopic }) => {
    // State
    const [genStep, setGenStep] = useState<1 | 2>(1);
    const [manualTopic, setManualTopic] = useState('');
    const [selectedTopics, setSelectedTopics] = useState<string[]>([]);
    const [genCount, setGenCount] = useState<1 | 2 | 3>(1);
    const [preSelectedImageMode, setPreSelectedImageMode] = useState<ImageSourceType>('none');
    const [selectedGenAccountId, setSelectedGenAccountId] = useState<string>(''); 
    const [generatedPosts, setGeneratedPosts] = useState<GeneratedPost[]>([]);
    const [isGenerating, setIsGenerating] = useState(false);
    const [isRegeneratingImage, setIsRegeneratingImage] = useState<string | null>(null);
    const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
    const [loadingTrends, setLoadingTrends] = useState(false);
    const [trendError, setTrendError] = useState('');

    // Effects
    useEffect(() => {
        if (accounts.length > 0) {
            const currentSelectionExists = accounts.some(a => a.id === selectedGenAccountId);
            if (!selectedGenAccountId || !currentSelectionExists) {
                setSelectedGenAccountId(accounts[0].id);
            }
        }
    }, [accounts]);

    // Handle Initial Topic from Stock Market
    useEffect(() => {
        if (initialTopic) {
            setSelectedTopics([initialTopic]);
            setManualTopic(initialTopic); // Also set manual so it persists visually if deselected
            setGenStep(2); // Jump directly to Step 2
        }
    }, [initialTopic]);

    const loadTrends = async (overrideKeyword?: string) => {
        if (!user) return alert("請先登入");

        // [BILLING] Trend Search: 3 Points
        const COST = 3; 
        const allowed = await checkAndUseQuota(user.user_id, COST, 'TREND_SEARCH');
        if (!allowed) return; 

        onQuotaUpdate();
        setLoadingTrends(true);
        setTrendError('');
        setTrendingTopics([]);

        try {
            const query = overrideKeyword || manualTopic || settings.industry || '台灣熱門時事';
            const trends = await getTrendingTopics(query);
            if (trends.length === 0) setTrendError("目前找不到相關新聞，請嘗試手動輸入其他話題。");
            setTrendingTopics(trends);
        } catch (e: any) {
            console.warn("Trend load error", e);
            setTrendError("無法載入即時趨勢，請檢查網路或稍後再試。");
        } finally {
            setLoadingTrends(false);
        }
    };

    const selectTopic = (title: string) => {
        if (selectedTopics.includes(title)) setSelectedTopics([]);
        else { setSelectedTopics([title]); setManualTopic(''); }
    };

    const handleManualTopicChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setManualTopic(e.target.value);
        if (e.target.value) setSelectedTopics([]);
    };

    const proceedToGenerateUI = () => {
        if (selectedTopics.length === 0 && !manualTopic) return alert("請先選擇或輸入一個話題");
        setGenStep(2);
    };

    const calculateCost = (count: number, mode: ImageSourceType) => {
        // [BILLING CONFIGURATION]
        // Text Only: 3 points
        // Stock Image: 6 points (3 Text + 3 Image)
        // AI Image: 8 points (3 Text + 5 Image)
        const baseCost = 3; 
        let extraCost = 0;

        if (mode === 'ai') extraCost = 5; 
        else if (mode === 'stock') extraCost = 3;
        else if (mode === 'news') extraCost = 1; // Small fee for processing/fetching news image

        return (baseCost + extraCost) * count;
    };

    const handleGenerateBatch = async () => {
        if (!user) return alert("請先登入");
        const topicSource = selectedTopics.length > 0 ? selectedTopics[0] : manualTopic;
        if (!topicSource) return alert("無效話題");

        const targetAccount = accounts.find(a => a.id === selectedGenAccountId);
        if (!targetAccount) return alert("錯誤：請先在上方選單選擇要發文的帳號");

        const totalCost = calculateCost(genCount, preSelectedImageMode);
        if (!confirm(`確定為帳號「${targetAccount.username}」生成 ${genCount} 篇貼文？\n\n消耗：${totalCost} 點配額`)) return;

        const allowed = await checkAndUseQuota(user.user_id, totalCost, 'THREADS_BATCH_GEN', { count: genCount, mode: preSelectedImageMode });
        if (!allowed) return; 
        onQuotaUpdate();

        setIsGenerating(true);
        setGeneratedPosts([]);

        try {
            const instruction = getThreadsSystemInstruction(
                targetAccount.accountType || 'personal',
                targetAccount.styleGuide,
                targetAccount.safetyFilter
            );

            const results = await generateThreadsBatch(topicSource, genCount, settings, [instruction]);
            const sourceTopicData = trendingTopics.find(t => t.title === topicSource);
            const initialNewsImg = sourceTopicData?.imageUrl;
            const newsUrl = sourceTopicData?.url;

            const newPosts: GeneratedPost[] = await Promise.all(results.map(async (r, i) => {
                let finalMode = preSelectedImageMode;
                let finalImageUrl = undefined;
                let errorLog = undefined;
                const uniqueSeed = Date.now().toString() + i;

                if (finalMode === 'ai') {
                    const encoded = encodeURIComponent(r.imagePrompt);
                    finalImageUrl = `https://image.pollinations.ai/prompt/${encoded}?n=${uniqueSeed}&model=flux`;
                } else if (finalMode === 'stock') {
                    finalImageUrl = generateStockUrl(r.imageQuery || r.imagePrompt, uniqueSeed);
                } else if (finalMode === 'news') {
                    if (initialNewsImg) finalImageUrl = initialNewsImg;
                    else if (newsUrl) {
                        const ogImg = await fetchNewsImageFromUrl(newsUrl);
                        if (ogImg) finalImageUrl = ogImg;
                    }
                    if (!finalImageUrl) {
                        try {
                           finalImageUrl = generateStockUrl(`News photo about ${topicSource}, realistic, journalism style`, uniqueSeed);
                        } catch (e) { finalMode = 'none'; errorLog = '無法取得新聞圖片'; }
                    }
                }

                return {
                    id: Date.now() + '_' + i,
                    topic: topicSource,
                    caption: r.caption,
                    imagePrompt: r.imagePrompt,
                    imageQuery: r.imageQuery,
                    newsImageUrl: finalMode === 'news' ? finalImageUrl : undefined,
                    imageUrl: (finalMode === 'ai' || finalMode === 'stock' || finalMode === 'news') ? finalImageUrl : undefined,
                    imageSourceType: finalMode,
                    log: errorLog,
                    status: 'idle',
                    targetAccountId: targetAccount.id
                };
            }));

            setGeneratedPosts(newPosts);
        } catch (e: any) {
            alert(`生成失敗: ${e.message}`);
        } finally {
            setIsGenerating(false);
        }
    };

    const getPreviewUrl = (post: GeneratedPost) => {
        if (post.imageSourceType === 'upload' && post.uploadedImageBase64) return post.uploadedImageBase64;
        if (post.imageSourceType === 'news' && post.newsImageUrl) return post.newsImageUrl;
        if (post.imageUrl) return post.imageUrl;
        return '';
    };

    const handleImageModeChange = async (post: GeneratedPost, newMode: ImageSourceType) => {
        if (newMode === 'stock' || newMode === 'ai') { 
            if (!user) return alert("請先登入");

            // [BILLING] Threads Image Regen
            // Stock Image Cost = 3 (Derived from Total 6 - Text 3)
            // AI Image Cost = 5 (Derived from Total 8 - Text 3)
            const COST = newMode === 'ai' ? 5 : 3;

            const allowed = await checkAndUseQuota(user.user_id, COST, 'THREADS_REGEN_IMAGE');
            if (!allowed) return; 
            onQuotaUpdate();

            setIsRegeneratingImage(post.id);
            const newSeed = Date.now().toString() + Math.floor(Math.random() * 9999);
            const visualSubject = post.imageQuery || post.topic; 
            const newUrl = generateStockUrl(visualSubject, newSeed);

            setTimeout(() => {
                setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, imageSourceType: newMode, imageUrl: newUrl } : p));
                setIsRegeneratingImage(null);
            }, 500); 
        } else {
            setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, imageSourceType: newMode } : p));
        }
    };

    const handlePublish = async (post: GeneratedPost) => {
        if (!post.targetAccountId) return alert("錯誤：未指定發佈帳號");
        const acc = accounts.find(a => a.id === post.targetAccountId);
        if (!acc) return alert("錯誤：找不到對應的帳號資料，請檢查帳號是否已被移除。");
        if (!post.caption) return alert("內容為空，無法發佈");

        setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'publishing', log: '發佈中...' } : p));
        try {
            const imgUrl = post.imageSourceType === 'none' ? undefined : getPreviewUrl(post);
            const res = await publishThreadsPost(acc, post.caption, imgUrl);
            if (res.success) {
                setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'done', log: '發佈成功！' } : p));
            } else {
                setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'failed', log: `發佈失敗: ${res.error}` } : p));
                alert(`發佈失敗: ${res.error}`);
            }
        } catch (e: any) {
            setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'failed', log: `系統錯誤: ${e.message}` } : p));
        }
    };

    if (loadingTrends) return <LoadingOverlay message="正在搜尋熱門話題" detail="AI 正在分析全網新聞與社群趨勢..." />;
    if (isGenerating) return <LoadingOverlay message="AI 正在量產 Threads 貼文" detail={`正在模擬 ${genCount} 篇不同語氣的真實貼文，並準備圖片中...`} />;

    return (
        <div className="space-y-6">
            {genStep === 1 && (
                <div className="bg-card p-6 rounded-xl border border-gray-700">
                     <h3 className="text-xl font-bold text-white mb-4">步驟 1: 選擇話題</h3>
                     <div className="mb-6 p-4 bg-dark/50 rounded-lg border border-gray-600">
                         <label className="block text-xs text-gray-400 mb-2 font-bold uppercase tracking-wider">第一步：設定或搜尋話題</label>
                         <div className="flex flex-col md:flex-row gap-2">
                             <input 
                                 value={manualTopic} 
                                 onChange={handleManualTopicChange} 
                                 className="flex-1 bg-dark border border-gray-600 rounded p-3 text-white placeholder-gray-500 focus:border-primary outline-none transition-colors" 
                                 placeholder="輸入關鍵字 (例如: AI, 美食, 房地產)..." 
                             />
                             <button 
                                 onClick={() => loadTrends()} 
                                 className="bg-indigo-600 hover:bg-indigo-500 text-white px-6 py-3 md:py-0 rounded font-bold transition-colors whitespace-nowrap flex items-center justify-center gap-2"
                             >
                                 搜尋趨勢 (3點)
                             </button>
                         </div>
                         <p className="text-[10px] text-gray-500 mt-2">提示：輸入關鍵字後點擊「搜尋」，AI 將為您挖掘該領域的最新熱門新聞。</p>
                     </div>
                     <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mb-4 max-h-[60vh] overflow-y-auto custom-scrollbar p-1">
                          <div onClick={() => loadTrends(settings.industry)} className="flex flex-col items-center justify-center bg-gray-800/50 border border-gray-600 hover:border-gray-400 rounded-lg p-6 cursor-pointer min-h-[160px] text-center shadow-lg transition-transform active:scale-95 group">
                              <span className="text-lg font-bold text-gray-300 group-hover:text-white">挖掘綜合熱門靈感</span>
                              <span className="text-[10px] bg-primary/20 text-primary px-2 py-0.5 rounded mt-2 font-bold tracking-wider">3 點數</span>
                              <p className="text-xs text-gray-500 mt-2">查看 {settings.industry || '台灣'} 目前最紅的話題</p>
                          </div>
                          {trendingTopics.map((t, i) => (
                              <div key={i} onClick={() => selectTopic(t.title)} className={`flex flex-col justify-between p-4 rounded-lg border cursor-pointer min-h-[160px] transition-all relative overflow-hidden ${selectedTopics.includes(t.title) ? 'bg-primary/20 border-primary ring-2 ring-primary' : 'bg-dark border-gray-700 hover:border-gray-500'}`}>
                                  {t.imageUrl && <div className="absolute inset-0 opacity-10 bg-cover bg-center z-0" style={{backgroundImage: `url(${t.imageUrl})`}}></div>}
                                  <div className="relative z-10">
                                      <h4 className="font-bold text-white text-base line-clamp-2 mb-2 leading-tight">{t.title}</h4>
                                      <p className="text-xs text-gray-400 line-clamp-3 leading-relaxed">{t.description || "點擊查看詳情，AI 將自動延伸話題..."}</p>
                                  </div>
                                  <div className="relative z-10 mt-2 text-[10px] text-gray-500 flex justify-between items-center">
                                      <span>來源: {t.url ? new URL(t.url).hostname.replace('www.', '') : 'News'}</span>
                                      {selectedTopics.includes(t.title) && <span className="text-primary font-bold">✓ 已選擇</span>}
                                  </div>
                              </div>
                          ))}
                     </div>
                     <div className="mt-6 flex justify-end"><button onClick={proceedToGenerateUI} className="bg-primary hover:bg-blue-600 text-white px-8 py-3 rounded font-bold shadow-lg w-full md:w-auto">下一步</button></div>
                </div>
            )}

            {genStep === 2 && (
                <div className="space-y-6">
                    <div className="bg-card p-6 rounded-xl border border-gray-700">
                         <div className="flex justify-between items-center mb-6">
                             <h3 className="text-xl font-bold text-white">步驟 2: 生成與發佈</h3>
                             <button onClick={() => setGenStep(1)} className="text-sm text-gray-400 hover:text-white border border-gray-600 px-3 py-1 rounded hover:bg-gray-700 transition-colors">↩ 返回選題</button>
                         </div>
                         <div className="mb-6 bg-blue-900/20 p-4 rounded border border-blue-800">
                             <label className="block text-sm text-blue-300 font-bold mb-2">1. 選擇發文帳號 (決定語氣與人設) *</label>
                             <select value={selectedGenAccountId} onChange={(e) => setSelectedGenAccountId(e.target.value)} className="w-full bg-dark border border-blue-500 rounded p-3 text-white">
                                 {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.username} ({acc.accountType === 'brand' ? '品牌' : '個人'})</option>)}
                              </select>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                             <div className="bg-dark/50 p-4 rounded border border-gray-600"><label className="block text-sm text-gray-400 mb-2">當前話題</label><div className="font-bold text-xl text-white">{selectedTopics[0] || manualTopic}</div></div>
                             <div className="space-y-4">
                                 <div><label className="block text-sm text-gray-400 mb-1">數量</label><div className="flex gap-2">{[1,2,3].map(n => <button key={n} onClick={() => setGenCount(n as any)} className={`flex-1 py-2 rounded border ${genCount === n ? 'bg-white text-black' : 'border-gray-600'}`}>{n}</button>)}</div></div>
                                 <div><label className="block text-sm text-gray-400 mb-1">圖片</label><select value={preSelectedImageMode} onChange={(e) => setPreSelectedImageMode(e.target.value as any)} className="w-full bg-dark border border-gray-600 rounded p-2 text-white"><option value="none">無圖片 (3點)</option><option value="stock">擬真圖庫 (6點)</option><option value="ai">AI繪圖 (8點)</option></select></div>
                             </div>
                         </div>
                         <button onClick={handleGenerateBatch} disabled={!selectedGenAccountId} className="w-full bg-gradient-to-r from-pink-600 to-purple-600 text-white py-4 rounded-xl font-bold text-lg shadow-lg">生成貼文</button>
                    </div>

                    {generatedPosts.length > 0 && (
                        <div className="space-y-8">
                            {generatedPosts.map((post) => (
                                <div key={post.id} className="bg-card rounded-xl border border-gray-700 overflow-hidden flex flex-col md:flex-row">
                                    <div className="w-full md:w-1/3 bg-black flex items-center justify-center relative min-h-[300px]">
                                        {getPreviewUrl(post) ? (
                                            <ImagePreview src={getPreviewUrl(post)} alt="Generated Content" />
                                        ) : <span className="text-gray-500">無圖片</span>}
                                        <div className="absolute bottom-2 left-2 flex gap-2">
                                            <button onClick={() => handleImageModeChange(post, 'stock')} disabled={isRegeneratingImage === post.id} className="text-xs bg-gray-700 hover:bg-gray-600 text-white px-3 py-2 rounded shadow-lg font-bold border border-gray-500 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-1">
                                                {isRegeneratingImage === post.id ? (<><div className="loader w-3 h-3 border-2 border-t-white"></div>生成中...</>) : '隨機換圖 (3點)'}
                                            </button>
                                        </div>
                                    </div>
                                    <div className="flex-1 p-6 flex flex-col">
                                        <textarea value={post.caption} onChange={(e) => setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, caption: e.target.value } : p))} className="w-full flex-1 bg-dark border border-gray-600 rounded p-3 text-white mb-4 resize-none" />
                                        <div className="flex justify-between items-center">
                                            <span className={`text-xs font-bold ${post.status === 'done' ? 'text-green-400' : post.status === 'failed' ? 'text-red-400' : 'text-gray-500'}`}>{post.log || (post.status === 'idle' ? '準備就緒' : '')}</span>
                                            <button onClick={() => handlePublish(post)} disabled={post.status === 'publishing' || post.status === 'done'} className={`px-6 py-3 rounded font-bold transition-all ${post.status === 'done' ? 'bg-green-600 text-white cursor-default' : 'bg-white text-black hover:bg-gray-200'}`}>
                                                {post.status === 'publishing' ? '發佈中...' : post.status === 'done' ? '已發佈' : '立即發佈'}
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

export default ContentGenerator;

